const t=[{id:1,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港四季酒店",question:"香港四季酒店 (Four Seasons)",options:["中西區","油尖旺區","灣仔區"],correctAnswer:0,explanation:"位於中環核心金融區，坐擁多間米芝蓮星級餐廳（龍景軒、Caprice），政商名流首選。"},{id:2,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港文華東方酒店",question:"香港文華東方酒店 (Mandarin Oriental)",options:["灣仔區","中西區","九龍城區"],correctAnswer:1,explanation:"位於中環，百年東方傳奇服務、著名的玫瑰果醬下午茶與文華扒房聞名。"},{id:3,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港居舍",question:"香港居舍 (The Upper House)",options:["深水埗區","沙田區","中西區"],correctAnswer:2,explanation:"位於金鐘，由著名設計師傅厚民設計，大隱於市的極簡奢華，極具私密感。"},{id:4,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港美利酒店",question:"香港美利酒店 (The Murray)",options:["中西區","東區","荃灣區"],correctAnswer:0,explanation:"位於金鐘，政府古蹟大樓活化，標誌性三層高白色拱門建築，現代與典雅結合。"},{id:5,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港港麗酒店",question:"香港港麗酒店 (Conrad)",options:["油尖旺區","中西區","南區"],correctAnswer:1,explanation:"位於金鐘，高層俯瞰維港與山頂景觀，行政酒廊服務極佳。"},{id:6,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港港島香格里拉大酒店",question:"香港港島香格里拉大酒店",options:["屯門區","觀塘區","中西區"],correctAnswer:2,explanation:"位於金鐘，經典歐洲宮廷風結合東方元素，大堂擁有亞洲最大的壁畫。"},{id:7,section:"酒店/旅宿",sectionName:"頂級奢華",district:"灣仔區",to:"香港萬麗海景酒店",question:"香港萬麗海景酒店 (Renaissance)",options:["灣仔區","西貢區","大埔區"],correctAnswer:0,explanation:"緊鄰灣仔會展中心，大面落地窗直面維港，萬豪旗下高CP值海景房。"},{id:8,section:"酒店/旅宿",sectionName:"頂級奢華",district:"灣仔區",to:"香港瑞吉酒店",question:"香港瑞吉酒店 (St. Regis)",options:["離島區","灣仔區","油尖旺區"],correctAnswer:1,explanation:"位於灣仔，招牌管家服務，室內設計極具法式與港式美學融合感。"},{id:9,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"中環石板街酒店",question:"中環．石板街酒店 (The Pottinger)",options:["黃大仙區","葵青區","中西區"],correctAnswer:2,explanation:"位於中環古老石板街旁，設計巧妙融入老香港殖民地與復古情懷。"},{id:10,section:"酒店/旅宿",sectionName:"頂級奢華",district:"灣仔區",to:"明怡美憬閣精選酒店",question:"明怡美憬閣精選酒店 (AKI MGallery)",options:["灣仔區","東區","北區"],correctAnswer:0,explanation:"灣仔區少見的和風榻榻米設計，極簡日系閣樓風精品酒店。"},{id:11,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"宜必思香港中上環酒店",question:"宜必思香港中上環酒店 (Ibis)",options:["深水埗區","中西區","油尖旺區"],correctAnswer:1,explanation:"上環經典經濟連鎖，樓下有叮叮車，高層享高性價比海景，預算有限者首選。"},{id:12,section:"酒店/旅宿",sectionName:"頂級奢華",district:"灣仔區",to:"夏利酒店",question:"夏利酒店 (The Hari Hong Kong)",options:["沙田區","元朗區","灣仔區"],correctAnswer:2,explanation:"位於灣仔與銅鑼灣交界，英倫紳士風格設計，洋溢時尚與藝術氣息。"},{id:13,section:"酒店/旅宿",sectionName:"網紅海景",district:"灣仔區",to:"香港柏寧酒店",question:"香港柏寧酒店 (The Park Lane)",options:["灣仔區","東區","油尖旺區"],correctAnswer:0,explanation:"位於銅鑼灣市中心，頂樓 SKYE 天台酒吧俯瞰維園與維港夜景。"},{id:14,section:"酒店/旅宿",sectionName:"網紅海景",district:"東區",to:"香港維港凱悅尚萃酒店",question:"香港維港凱悅尚萃酒店 (Hyatt Centric)",options:["中西區","東區","九龍城區"],correctAnswer:1,explanation:"位於北角海旁，全客房面海，頂樓無邊際泳池是極受歡迎的打卡聖地。"},{id:15,section:"酒店/旅宿",sectionName:"網紅海景",district:"東區",to:"二十一居",question:"二十一居 (Tuve)",options:["南區","西貢區","東區"],correctAnswer:2,explanation:"鄰近天后站，極致冷淡風、清水模與黑鐵工業設計酒店，深受設計師喜愛。"},{id:16,section:"酒店/旅宿",sectionName:"網紅海景",district:"灣仔區",to:"香港銅鑼灣皇冠假日酒店",question:"香港銅鑼灣皇冠假日酒店",options:["灣仔區","觀塘區","深水埗區"],correctAnswer:0,explanation:"位於銅鑼灣，頂樓設有無邊際泳池及池畔酒吧，可俯瞰跑馬地馬場。"},{id:17,section:"酒店/旅宿",sectionName:"網紅海景",district:"觀塘區",to:"廿一由八",question:"廿一由八 (Twenty One From Eight)",options:["中西區","觀塘區","油尖旺區"],correctAnswer:1,explanation:"位於觀塘，結合木工工作室、原木家具展廳、咖啡廳與住宿的文青空間。"},{id:18,section:"酒店/旅宿",sectionName:"度假親子",district:"南區",to:"香港富麗敦海洋公園酒店",question:"香港富麗敦海洋公園酒店 (The Fullerton)",options:["離島區","西貢區","南區"],correctAnswer:2,explanation:"南區頂級臨海度假酒店，每間客房皆享南中國海景，擁巨大無邊際泳池與多個兒童主題房。"},{id:19,section:"酒店/旅宿",sectionName:"度假親子",district:"南區",to:"香港海洋公園萬豪酒店",question:"香港海洋公園萬豪酒店",options:["南區","荃灣區","沙田區"],correctAnswer:0,explanation:"緊鄰海洋公園，大堂設有 16 米高巨型水族缸，非常適合家庭客出遊。"},{id:20,section:"酒店/旅宿",sectionName:"度假親子",district:"南區",to:"奧華時尚精品酒店",question:"奧華．時尚精品酒店 (Ovolo Southside)",options:["東區","南區","油尖旺區"],correctAnswer:1,explanation:"位於黃竹坑，由舊倉庫改建，充滿當代藝術、塗鴉與強烈工業設計感。"},{id:21,section:"酒店/旅宿",sectionName:"頂級奢華",district:"油尖旺區",to:"香港瑰麗酒店",question:"香港瑰麗酒店 (Rosewood)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:2,explanation:"尖沙咀 Victoria Dockside 地標，絕美維港海景、極致莊園風設計與頂級水療。"},{id:22,section:"酒店/旅宿",sectionName:"頂級奢華",district:"油尖旺區",to:"香港半島酒店",question:"香港半島酒店 (The Peninsula)",options:["油尖旺區","中西區","東區"],correctAnswer:0,explanation:"尖沙咀傳奇地標，全港歷史最悠久酒店，以英式下午茶、直升機坪、勞斯萊斯車隊聞名。"},{id:23,section:"酒店/旅宿",sectionName:"頂級奢華",district:"油尖旺區",to:"香港麗晶酒店",question:"香港麗晶酒店 (Regent)",options:["灣仔區","油尖旺區","南區"],correctAnswer:1,explanation:"重返尖沙咀一線海旁，無邊際落地窗維港視覺效果震撼，擁米芝蓮二星麗晶軒。"},{id:24,section:"酒店/旅宿",sectionName:"頂級奢華",district:"油尖旺區",to:"香港麗思卡爾頓酒店",question:"香港麗思卡爾頓酒店 (Ritz-Carlton)",options:["中西區","沙田區","油尖旺區"],correctAnswer:2,explanation:"九龍站 ICC 頂層（102-118樓），全球最高酒店之一，雲端俯瞰全港景觀。"},{id:25,section:"酒店/旅宿",sectionName:"頂級奢華",district:"油尖旺區",to:"W香港酒店",question:"W 香港酒店 (W Hong Kong)",options:["油尖旺區","灣仔區","離島區"],correctAnswer:0,explanation:"位於九龍站，主打前衛、絢麗夜店風與電音文化，76樓擁有全港最高戶外屋頂泳池。"},{id:26,section:"酒店/旅宿",sectionName:"頂級奢華",district:"油尖旺區",to:"K11ARTUS",question:"K11 ARTUS (寓館)",options:["中西區","油尖旺區","東區"],correctAnswer:1,explanation:"位於尖沙咀 K11 Musea 上蓋，充滿藝術品的頂級奢華酒店式公寓，設有私人間觀景陽台。"},{id:27,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"唯港薈",question:"唯港薈 (Hotel ICON)",options:["九龍城區","黃大仙區","油尖旺區"],correctAnswer:2,explanation:"位於尖東，由香港理工大學經營的教學酒店，其 The Market 自助餐全港人氣極高。"},{id:28,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"香港喜來登酒店",question:"香港喜來登酒店 (Sheraton)",options:["油尖旺區","灣仔區","中西區"],correctAnswer:0,explanation:"尖沙咀核心海旁地段，頂樓 Sky Lounge 是觀賞維港幻彩詠香江的老牌景點。"},{id:29,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"馬哥孛羅香港酒店",question:"馬哥孛羅香港酒店",options:["荃灣區","油尖旺區","東區"],correctAnswer:1,explanation:"位於尖沙咀，直接連通海港城購物中心，對購物行程極度便利。"},{id:30,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"香港九龍香格里拉大酒店",question:"香港九龍香格里拉大酒店",options:["中西區","北區","油尖旺區"],correctAnswer:2,explanation:"位於尖東，經典老牌奢華代表，客房空間在尖沙咀一線海景酒店中相對寬敞。"},{id:31,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"香港朗廷酒店",question:"香港朗廷酒店 (The Langham)",options:["油尖旺區","灣仔區","大埔區"],correctAnswer:0,explanation:"位於尖沙咀，主打英倫古典奢華風與粉紅少女心細節，館內唐閣為米芝蓮三星中餐廳。"},{id:32,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"百樂酒店",question:"百樂酒店 (Park Hotel)",options:["深水埗區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖沙咀金馬倫道，周邊生活機能、逛街交通極方便，自由行高CP值熱門選擇。"},{id:33,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"帝樂文娜公館",question:"帝樂文娜公館 (The Luxe Manor)",options:["屯門區","元朗區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀，全港首間以薩爾瓦多·達利超現實主義為設計靈感的精品藝術酒店。"},{id:34,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"富豪九龍酒店",question:"富豪九龍酒店 (Regal Kowloon)",options:["油尖旺區","中西區","南區"],correctAnswer:0,explanation:"位於尖東，採法式歐陸風情設計，商務差旅及觀光團體旅遊的老牌經典。"},{id:35,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"帝京酒店",question:"帝京酒店 (Royal Plaza)",options:["沙田區","油尖旺區","西貢區"],correctAnswer:1,explanation:"位於旺角東站上蓋，連通 MOKO 新世紀廣場，房間寬敞，往返內地及東鐵沿線極便利。"},{id:36,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港康得思酒店",question:"香港康得思酒店 (Cordis)",options:["灣仔區","東區","油尖旺區"],correctAnswer:2,explanation:"位於旺角核心地段，直通朗豪坊商場與地鐵站，頂樓設有高空戶外泳池與水療。"},{id:37,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港逸東酒店",question:"香港逸東酒店 (Eaton HK)",options:["油尖旺區","中西區","深水埗區"],correctAnswer:0,explanation:"位於佐敦，融合復古港式霓虹美學與本土藝術，大力宣揚環保與多元包容社區文化。"},{id:38,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"木的地酒店",question:"木的地酒店 (Madera Hollywood)",options:["大埔區","油尖旺區","葵青區"],correctAnswer:1,explanation:"佐敦館主打西班牙南歐繽紛風，中環精品館則主打荷里活巨星復古奢華壁畫風。"},{id:39,section:"酒店/旅宿",sectionName:"度假親子",district:"深水埗區",to:"YHA美荷樓青年旅舍",question:"YHA美荷樓青年旅舍",options:["九龍城區","中西區","深水埗區"],correctAnswer:2,explanation:"位於石硤尾，由二級歷史建築（香港早期公屋徙置大廈）活化，內設歷史生活館。"},{id:40,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"城景國際",question:"城景國際 (The Cityview)",options:["油尖旺區","灣仔區","觀塘區"],correctAnswer:0,explanation:"鄰近油麻地地鐵站，地理位置極佳，主打綠色環保概念與高性價比宿旅。"},{id:41,section:"酒店/旅宿",sectionName:"度假親子",district:"沙田區",to:"帝逸酒店",question:"帝逸酒店 (ALVA HOTEL BY ROYAL)",options:["北區","沙田區","元朗區"],correctAnswer:1,explanation:"位於沙田城門河畔，提供免費單車租借、高科技智能客房與精緻屋頂無邊際泳池。"},{id:42,section:"酒店/旅宿",sectionName:"度假親子",district:"沙田區",to:"香港沙田凱悅酒店",question:"香港沙田凱悅酒店",options:["大埔區","西貢區","沙田區"],correctAnswer:2,explanation:"鄰近香港中文大學與大學站，依山傍水遠離鬧市，綠意盎然，度假感十足。"},{id:43,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"悅來酒店",question:"悅來酒店 (Panda Hotel)",options:["荃灣區","葵青區","屯門區"],correctAnswer:0,explanation:"荃灣地標性「熊貓酒店」，房間數量多且性價比高，周邊商圈生活配套極成熟。"},{id:44,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"帝景酒店",question:"帝景酒店 (Royal View Hotel)",options:["離島區","荃灣區","南區"],correctAnswer:1,explanation:"位於汀九青山公路旁，臨海而建，能飽覽青馬大橋與汀九橋壯麗海景。"},{id:45,section:"酒店/旅宿",sectionName:"度假親子",district:"屯門區",to:"香港黃金海岸酒店",question:"香港黃金海岸酒店",options:["西貢區","大嶼山","屯門區"],correctAnswer:2,explanation:"位於屯門黃金泳灘旁，全港最知名的歐陸風親子海景沙灘度假酒店。"},{id:46,section:"酒店/旅宿",sectionName:"度假親子",district:"屯門區",to:"悦品度假酒店屯門",question:"悦品度假酒店 (屯門)",options:["屯門區","元朗區","北區"],correctAnswer:0,explanation:"鄰近屯門站，以世界鐵路火車、日本、泰國、希臘等異國風情主題打造的特色休閒酒店。"},{id:47,section:"酒店/旅宿",sectionName:"度假親子",district:"西貢區",to:"香港九龍東皇冠假日酒店",question:"香港九龍東皇冠假日酒店",options:["觀塘區","西貢區","黃大仙區"],correctAnswer:1,explanation:"位於將軍澳地鐵站上蓋，交通極便利，高層頂樓設有景觀開揚的星空酒吧。"},{id:48,section:"酒店/旅宿",sectionName:"樂園商務",district:"離島區",to:"香港迪士尼樂園酒店",question:"香港迪士尼樂園酒店",options:["荃灣區","南區","離島區"],correctAnswer:2,explanation:"大嶼山迪士尼度假區內，宏偉的維多利亞式宮殿風格，翠樂庭餐廳可與迪士尼角色用餐。"},{id:49,section:"酒店/旅宿",sectionName:"樂園商務",district:"離島區",to:"迪士尼探索家度假酒店",question:"迪士尼探索家度假酒店",options:["離島區","葵青區","屯門區"],correctAnswer:0,explanation:"以亞非南美等四大洲探險為主題，園林景觀極大，度假休閒感為迪士尼三間中最強。"},{id:50,section:"酒店/旅宿",sectionName:"樂園商務",district:"離島區",to:"迪士尼好萊塢酒店",question:"迪士尼好萊塢酒店",options:["油尖旺區","離島區","中西區"],correctAnswer:1,explanation:"採好萊塢裝飾藝術 (Art Deco) 風格設計，將經典電影魔幻元素與迪士尼動畫完美結合。"},{id:51,section:"酒店/旅宿",sectionName:"樂園商務",district:"離島區",to:"香港東涌世茂喜來登酒店",question:"香港東涌世茂喜來登酒店",options:["西貢區","元朗區","離島區"],correctAnswer:2,explanation:"位於東涌海畔，遠眺大嶼山與機場海景，鄰近東薈城名店倉 Outlet，兼顧購物與度假。"},{id:52,section:"酒店/旅宿",sectionName:"樂園商務",district:"離島區",to:"香港愉景灣酒店",question:"香港愉景灣酒店",options:["離島區","南區","荃灣區"],correctAnswer:0,explanation:"位於遠離市區的大嶼山愉景灣小鎮，擁有全港唯一的浪漫海濱白教堂。"},{id:53,section:"酒店/旅宿",sectionName:"樂園商務",district:"離島區",to:"香港天際萬豪酒店",question:"香港天際萬豪酒店 (SkyCity)",options:["中西區","離島區","油尖旺區"],correctAnswer:1,explanation:"赤鱲角機場區，緊鄰亞洲國際博覽館與香港國際機場，商務差旅與演唱會觀展首選。"},{id:54,section:"酒店/旅宿",sectionName:"樂園商務",district:"離島區",to:"麗豪航天城酒店",question:"麗豪航天城酒店 (Regala Skycity)",options:["荃灣區","葵青區","離島區"],correctAnswer:2,explanation:"坐落於赤鱲角航天城（11 SKIES），設計具現代感，無縫連接機場與大型購物娛樂商圈。"},{id:55,section:"酒店/旅宿",sectionName:"樂園商務",district:"西貢區",to:"WM酒店",question:"WM 酒店 (WM Hotel)",options:["西貢區","大埔區","南區"],correctAnswer:0,explanation:"位於西貢海濱，設有全白小禮堂與頂樓無邊際泳池，洋溢濃厚的東南亞海島度假村氛圍。"},{id:56,section:"酒店/旅宿",sectionName:"網紅海景",district:"東區",to:"香港東隅",question:"香港東隅 (EAST Hong Kong)",options:["東區","灣仔區","中西區"],correctAnswer:0,explanation:"位於太古城，設計時尚現代，頂樓天台酒吧 Sugar 坐擁極佳的維港東面海景。"},{id:57,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港置地文華東方酒店",question:"香港置地文華東方酒店 (The Landmark Mandarin Oriental)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:1,explanation:"位於中環置地廣場旁，主打當代前衛奢華與極高私密性，其水療中心及米芝蓮餐廳聲譽卓著。"},{id:58,section:"酒店/旅宿",sectionName:"網紅海景",district:"九龍城區",to:"香港嘉里酒店",question:"香港嘉里酒店 (Kerry Hotel Hong Kong)",options:["東區","南區","九龍城區"],correctAnswer:2,explanation:"位於紅磡海旁，主打城市度假風，擁有超大戶外海景平台與無邊際泳池，視野極其開揚。"},{id:59,section:"酒店/旅宿",sectionName:"度假親子",district:"沙田區",to:"香港麗豪酒店",question:"香港麗豪酒店 (Regal Riverside Hotel)",options:["沙田區","大埔區","北區"],correctAnswer:0,explanation:"位於沙田城門河畔的老牌大型酒店，房間數量多，配套設施齊全，主打高性價比宿旅。"},{id:60,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"千禧新世界香港酒店",question:"千禧新世界香港酒店 (New World Millennium)",options:["灣仔區","油尖旺區","中西區"],correctAnswer:1,explanation:"位於尖東臨海地段，日系頂級服務管理，客房大面窗戶直面維多利亞港。"},{id:61,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"海景嘉福洲際酒店",question:"海景嘉福洲際酒店 (InterContinental Grand Stanford)",options:["東區","九龍城區","油尖旺區"],correctAnswer:2,explanation:"尖東經典五星級海景酒店，館內海景軒中餐廳與海景咖啡廊自助餐非常知名。"},{id:62,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港JW萬豪酒店",question:"香港JW萬豪酒店 (JW Marriott Hotel Hong Kong)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於金鐘太古廣場上蓋，交通極為便利，以高品質餐飲與一貫的穩健商務五星服務著稱。"},{id:63,section:"酒店/旅宿",sectionName:"網紅海景",district:"九龍城區",to:"都會海逸酒店",question:"都會海逸酒店 (Metropark Hotel Kowloon)",options:["深水埗區","九龍城區","黃大仙區"],correctAnswer:1,explanation:"位於紅磡站旁，緊鄰香港體育館（紅館），是觀看演唱會旅客的住宿首選。"},{id:64,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"帝豪酒店",question:"香港旺角帝盛酒店 (Dorsett Mongkok)",options:["沙田區","荃灣區","油尖旺區"],correctAnswer:2,explanation:"位於大角咀與旺角交界，主打現代輕奢與親子友善，曾多次榮獲環保與服務獎項。"},{id:65,section:"酒店/旅宿",sectionName:"網紅海景",district:"灣仔區",to:"香港六國酒店",question:"香港六國酒店 (Gloucester Luk Kwok Hong Kong)",options:["灣仔區","中西區","東區"],correctAnswer:0,explanation:"位於灣仔核心區，香港歷史悠久的現代化酒店，館內粵菜廳粵軒十分有名。"},{id:66,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"悅品酒店荃灣",question:"悅品酒店．荃灣 (COZl Hotel Tsuen Wan)",options:["葵青區","荃灣區","屯門區"],correctAnswer:1,explanation:"位於葵涌/荃灣交界，採取時尚溫馨設計，性價比極高，並設有親子專屬設施。"},{id:67,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"帝樂文娜公館",question:"帝樂文娜公館 (The Luxe Manor)",options:["離島區","北區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀諾士佛台旁，全港首家以奢華超現實主義及達利藝術為主題的精品酒店。"},{id:68,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港皇家太平洋酒店",question:"香港皇家太平洋酒店 (The Royal Pacific Hotel)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"坐落於尖沙咀廣東道中國客運碼頭上蓋，直通九龍公園，地理位置對中港往返極便利。"},{id:69,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港太子酒店",question:"香港太子酒店 (Prince Hotel, Marco Polo)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於尖沙咀海港城內，近年經全新翻新，風格變得繽紛時尚，極受購物旅客喜愛。"},{id:70,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港馬哥孛羅港威酒店",question:"香港馬哥孛羅港威酒店 (Gateway Hotel)",options:["黃大仙區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀廣東道，海港城三間馬哥孛羅系列酒店之一，主打潮流現代商務風。"},{id:71,section:"酒店/旅宿",sectionName:"網紅海景",district:"灣仔區",to:"香港諾富特世紀酒店",question:"香港諾富特世紀酒店 (Novotel Century Hong Kong)",options:["灣仔區","東區","南區"],correctAnswer:0,explanation:"位於灣仔核心地帶，鄰近會展中心與地鐵站，雅高旗下經典的高CP值商務五星選擇。"},{id:72,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"九龍酒店",question:"九龍酒店 (The Kowloon Hotel)",options:["中西區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀彌敦道，半島酒店正後方，直通尖沙咀地鐵站，以極致的黃金地段著稱。"},{id:73,section:"酒店/旅宿",sectionName:"網紅海景",district:"九龍城區",to:"八度海逸酒店",question:"八度海逸酒店 (Harbour Plaza 8 Degrees)",options:["黃大仙區","觀塘區","九龍城區"],correctAnswer:2,explanation:"位於土瓜灣，大堂採取獨特的傾斜「八度空間」視覺設計，客房寬敞且性價比高。"},{id:74,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"旭逸酒店荃灣",question:"旭逸酒店．荃灣 (Hotel Ease Tsuen Wan)",options:["荃灣區","葵青區","屯門區"],correctAnswer:0,explanation:"位於葵涌/荃灣工業區活化地帶，內部裝潢現代工業風，提供高性價比的舒適長短租服務。"},{id:75,section:"酒店/旅宿",sectionName:"網紅海景",district:"中西區",to:"香港萬怡酒店",question:"香港萬怡酒店 (Courtyard by Marriott Hong Kong)",options:["東區","中西區","南區"],correctAnswer:1,explanation:"位於西營盤海旁，萬豪旗下的高CP值輕奢商務酒店，多數房間享有開揚的維港西面海景。"},{id:76,section:"酒店/旅宿",sectionName:"樂園商務",district:"離島區",to:"諾富特東薈城酒店",question:"諾富特東薈城酒店 (Novotel Citygate Hong Kong)",options:["荃灣區","葵青區","離島區"],correctAnswer:2,explanation:"位於東涌，直通東薈城名店倉 Outlet與東涌站，是前往機場或大嶼山觀光的絕佳樞紐。"},{id:77,section:"酒店/旅宿",sectionName:"網紅海景",district:"灣仔區",to:"香港灣仔帝盛酒店",question:"香港灣仔帝盛酒店 (Dorsett Wanchai Hong Kong)",options:["灣仔區","東區","南區"],correctAnswer:0,explanation:"緊鄰跑馬地馬場，部分房間享有獨特的馬場景觀，提供多款主題家庭套房。"},{id:78,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角智選假日酒店",question:"香港旺角智選假日酒店 (Holiday Inn Express Mongkok)",options:["深水埗區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於旺角與油麻地交界，洲際旗下經典高CP值連鎖精品，生活逛街機能極好。"},{id:79,section:"酒店/旅宿",sectionName:"度假親子",district:"觀塘區",to:"旭逸雅捷酒店觀塘",question:"旭逸雅捷酒店．觀塘 (Hotel Ease Access Kwun Tong)",options:["九龍城區","觀塘區","西貢區"],correctAnswer:2,explanation:"位於東九龍核心商貿區，簡約現代的小型城市精品酒店，吸引年輕商務客。"},{id:80,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"宏基國際賓館",question:"宏基國際賓館 (Bishop Lei International House)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中半山高尚住宅區，由天主教香港教區營運，環境清幽且能俯瞰中環都會景致。"},{id:81,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"尖沙咀凱悅酒店",question:"尖沙咀凱悅酒店 (Hyatt Regency Hong Kong, Tsim Sha Tsui)",options:["中西區","油尖旺區","東區"],correctAnswer:1,explanation:"位於尖沙咀 K11 購物藝術館上蓋，直接連通地鐵站，客房景觀開揚，餐飲水準極高。"},{id:82,section:"酒店/旅宿",sectionName:"網紅海景",district:"灣仔區",to:"英皇駿景酒店",question:"英皇駿景酒店 (The Emperor Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔/跑馬地交界，由奢華名師打造內部室內設計，精緻典雅且具高CP值。"},{id:83,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港金域假日酒店",question:"香港金域假日酒店 (Holiday Inn Golden Mile)",options:["油尖旺區","深水埗區","九龍城區"],correctAnswer:0,explanation:"位於尖沙咀彌敦道黃金地段，以優越的親子家庭友善政策及便利的交通聞名。"},{id:84,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"晉逸精品酒店尖沙咀",question:"晉逸精品酒店．尖沙咀 (Butterfly on Prat)",options:["中西區","油尖旺區","灣仔區"],correctAnswer:1,explanation:"位於尖沙咀寶勒巷，主打色彩繽紛的流行時尚風，周邊食肆林立，自由行熱門。"},{id:85,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"華大盛品酒店",question:"華大盛品酒店 (Best Western Plus Hotel Hong Kong)",options:["東區","南區","中西區"],correctAnswer:2,explanation:"位於西營盤，傳統美式Best Western連鎖星級，空間實用，為高性價比的經濟型選擇。"},{id:86,section:"酒店/旅宿",sectionName:"網紅海景",district:"東區",to:"北角海逸酒店",question:"北角海逸酒店 (Harbour Plaza North Point)",options:["東區","灣仔區","九龍城區"],correctAnswer:0,explanation:"位於北角與鰂魚涌交界，鄰近地鐵站，多數客房享有東區維港海景，設有大型露天泳池。"},{id:87,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"富豪東方酒店",question:"富豪東方酒店 (Regal Oriental Hotel)",options:["黃大仙區","九龍城區","觀塘區"],correctAnswer:1,explanation:"位於九龍城，前臨舊啟德機場的歷史見證者，周邊以豐富的東南亞/潮州地道美食著稱。"},{id:88,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港大學數碼港艾美酒店",question:"香港數碼港艾美酒店 (Le Meridien Hong Kong, Cyberport)",options:["南區","灣仔區","中西區"],correctAnswer:2,explanation:"位於鋼綫灣數碼港，經全面科技感翻新，環境幽靜，主打法式藝術時尚與高科技體驗。"},{id:89,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"中環翡格酒店",question:"中環翡格酒店 (The Figo)",options:["中西區","油尖旺區","東區"],correctAnswer:0,explanation:"位於上環（鄰近中環），是一間非常精緻且著名寵物友善（Pet-friendly）的精品設計酒店。"},{id:90,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"佐敦逸東軒住客寓所",question:"佐敦逸東軒住客寓所 (Eaton Residences, Jordan)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"佐敦核心地段的精品酒店式公寓，配有簡易廚房，非常適合中長途商務或家庭旅客。"},{id:91,section:"酒店/旅宿",sectionName:"度假親子",district:"深水埗區",to:"旭逸雅捷酒店荔枝角",question:"旭逸雅捷酒店．荔枝角 (Hotel Ease Access Lai Chi Kok)",options:["葵青區","荃灣區","深水埗區"],correctAnswer:2,explanation:"位於荔枝角服裝批發商圈與地鐵站旁，空間簡約現代，深受商務客與自由行買手喜愛。"},{id:92,section:"酒店/旅宿",sectionName:"度假親子",district:"元朗區",to:"悅品天秀酒店元朗",question:"悅品天秀酒店．元朗 (COZl Hotel Wet Land)",options:["元朗區","屯門區","北區"],correctAnswer:0,explanation:"位於天水圍，緊鄰香港濕地公園，環境自然清幽，是探索新界大自然的極佳落腳點。"},{id:93,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"蘭桂坊酒店九如坊",question:"蘭桂坊酒店@九如坊 (Lan Kwai Fong Hotel @ Kau U Fong)",options:["灣仔區","中西區","東區"],correctAnswer:1,explanation:"位於中環九如坊，巧妙融合中國傳統絲綢古典風與現代精品美學，深得歐美遊客喜愛。"},{id:94,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"香港海景絲麗酒店",question:"香港海景絲麗酒店 (Silka Seaview Hotel)",options:["九龍城區","深水埗區","油尖旺區"],correctAnswer:2,explanation:"位於油麻地，鄰近廟街夜市，為絲麗連鎖旗下的經濟平價高性價比大眾酒店。"},{id:95,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"帝盛君豪酒店",question:"帝盛君豪酒店 (Dorsett Regency Hong Kong)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"帝盛集團於油尖旺打造的全新都會風格星級酒店，主打高科技智能客房與貼心旅遊服務。"},{id:96,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"長洲華威酒店",question:"長洲華威酒店 (Warwick Hotel Cheung Chau)",options:["南區","離島區","西貢區"],correctAnswer:1,explanation:"位於長洲東灣沙灘旁，香港少有的離島本土風情度假酒店，拉開窗簾即是沙灘海浪。"},{id:97,section:"酒店/旅宿",sectionName:"網紅海景",district:"九龍城區",to:"海逸豪園海逸君綽酒店",question:"九龍海逸君綽酒店 (Harbour Grand Kowloon)",options:["東區","油尖旺區","九龍城區"],correctAnswer:2,explanation:"位於黃埔海旁，擁有著名的頂樓露天玻璃幕牆泳池（網紅打卡極熱門）與頂級一線海景。"},{id:98,section:"酒店/旅宿",sectionName:"網紅海景",district:"東區",to:"港島海逸君綽酒店",question:"港島海逸君綽酒店 (Harbour Grand Hong Kong)",options:["東區","灣仔區","中西區"],correctAnswer:0,explanation:"位於炮台山海旁，每間客房均享維港景致，頂樓 Le 188° 餐廳坐擁 180 度超震撼視覺海景。"},{id:99,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"銀鑛灣渡假酒店",question:"銀鑛灣渡假酒店 (Silvermine Beach Resort)",options:["西貢區","離島區","荃灣區"],correctAnswer:1,explanation:"位於大嶼山梅窩銀河海灘旁，遠離城市喧囂，設有大型戶外BBQ及各種水上活動配套。"},{id:100,section:"酒店/旅宿",sectionName:"度假親子",district:"葵青區",to:"永倫800酒店",question:"永倫800酒店 (Winland 800 Hotel)",options:["荃灣區","屯門區","葵青區"],correctAnswer:2,explanation:"位於青衣島藍巴勒海峽旁，擁有極大規模的客房體量，是香港著名的超經濟型團體與自由行旅宿。"},{id:101,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港中環格蘭酒店",question:"香港中環格蘭酒店 (The Centric Central)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:0,explanation:"位於中環蘇豪區旁，融合當代藝術與極簡奢華，深受歐美商務客與高端自由行旅客青睞。"},{id:102,section:"酒店/旅宿",sectionName:"網紅海景",district:"九龍城區",to:"香港啟德帝盛酒店",question:"香港啟德帝盛酒店 (Dorsett Kai Tak)",options:["東區","九龍城區","觀塘區"],correctAnswer:1,explanation:"鄰近全新啟德體育園，坐擁舊啟德跑道及維港東面全新海景，設計充滿現代活力。"},{id:103,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"大澳文物酒店",question:"大澳文物酒店 (Tai O Heritage Hotel)",options:["西貢區","南區","離島區"],correctAnswer:2,explanation:"由歷史悠久的大澳舊警署活化而成，完美保留殖民地建築風格，僅提供少量極其珍貴的客房。"},{id:104,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港南洋酒店",question:"香港南洋酒店 (South Pacific Hotel)",options:["灣仔區","東區","中西區"],correctAnswer:0,explanation:"位於銅鑼灣與灣仔交界，外觀採標誌性的玻璃幕牆設計，周邊美食林立，性價比高。"},{id:105,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港恆豐酒店",question:"香港恆豐酒店 (Prudential Hotel)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於佐敦彌敦道上蓋，直通佐敦地鐵站，下樓即是恆豐中心商場，生活逛街機能極度發達。"},{id:106,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"龍堡國際",question:"龍堡國際 (BBP International House)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:2,explanation:"緊鄰尖沙咀九龍公園與柯士甸站，客房視野開揚，直面公園綠意或維港遠景，性價比極高。"},{id:107,section:"酒店/旅宿",sectionName:"網紅海景",district:"灣仔區",to:"香港問月酒店",question:"香港問月酒店 (Mira Moon Hotel)",options:["灣仔區","東區","南區"],correctAnswer:0,explanation:"美麗華集團旗下位於銅鑼灣的精品設計酒店，以中國傳統「中秋嫦娥奔月」神話為室內設計靈感。"},{id:108,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"美麗華酒店",question:"美麗華酒店 (The Mira Hong Kong)",options:["中西區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀彌敦道，直通美麗華廣場，設計主打潮流極簡科技風，附設極受歡迎的高空水療中心。"},{id:109,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"九龍香格里拉大酒店",question:"九龍香格里拉大酒店 (Kowloon Shangri-La)",options:["沙田區","九龍城區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀東部海旁，經典老牌頂級五星，客房面積寬敞，其中餐廳香宮獲米芝蓮星級榮譽。"},{id:110,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港JEN酒店",question:"香港 JEN 酒店 (Hotel Jen Hong Kong by Shangri-La)",options:["中西區","東區","南區"],correctAnswer:0,explanation:"位於西環石塘咀，香格里拉集團旗下年輕副牌，直通香港大學站，頂樓擁絕美海景露天泳池。"},{id:111,section:"酒店/旅宿",sectionName:"度假親子",district:"觀塘區",to:"九龍東如心酒店",question:"九龍東如心酒店 (Nina Hotel Island South East)",options:["九龍城區","觀塘區","西貢區"],correctAnswer:1,explanation:"位於牛頭角/觀塘商貿區，內部裝潢充滿現代都市質感，大堂設計與高層視野深受商務客喜愛。"},{id:112,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"荃灣西如心酒店",question:"荃灣西如心酒店 (Nina Hotel Tsuen Wan West)",options:["葵青區","屯門區","荃灣區"],correctAnswer:2,explanation:"雙子塔式建築地標，全港房間數量最多的五星級酒店之一，高層能飽覽藍巴勒海峽及汀九橋美景。"},{id:113,section:"酒店/旅宿",sectionName:"度假親子",district:"南區",to:"南灣如心酒店",question:"南灣如心酒店 (Nina Hotel Island South)",options:["南區","東區","中西區"],correctAnswer:0,explanation:"位於黃竹坑，鄰近海洋公園，背山面海，環境悠閒靜謐，是都市度假 Staycation 的平價好去處。"},{id:114,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港城景國際",question:"香港城景國際 (The Cityview Hong Kong)",options:["深水埗區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於油麻地窩打老道，地鐵站步入即達，主打四星級高綠化節能環保概念與極便利的市中心交通。"},{id:115,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"仕德福山景酒店",question:"仕德福山景酒店 (Stanford Hillview Hotel)",options:["九龍城區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"隱密地坐落於尖沙咀天文台山丘上，大隱於市，環境清幽且鬧中取靜，下山即到熱鬧的諾士佛台。"},{id:116,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"仕德福酒店",question:"仕德福酒店 (Stanford Hotel)",options:["油尖旺區","深水埗區","黃大仙區"],correctAnswer:0,explanation:"位於旺角豉油街，緊鄰女人街、波鞋街等旺角核心購物商圈，自由行旅客血拼的高 CP 值熱點。"},{id:117,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"晉逸海居精品酒店",question:"晉逸海居精品酒店．中環 (Butterfly on Wellington)",options:["灣仔區","中西區","東區"],correctAnswer:1,explanation:"位於中環威靈頓街，鄰近蘭桂坊及中環至半山自動扶梯，設計洋溢東方新古典精品美學。"},{id:118,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"木的地酒店佐敦",question:"木的地酒店．佐敦 (Madera Hong Kong Jordan)",options:["深水埗區","九龍城區","油尖旺區"],correctAnswer:2,explanation:"位於佐敦長樂街，主打西班牙繽紛陽光色彩設計，館內頂樓附設極具情調的復古藝術酒吧。"},{id:119,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"宜必思香港中上環",question:"宜必思香港中上環 (Ibis Hong Kong Central & Sheung Wan)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環德輔道西，色彩明快，高層部分客房享有高性價比的維港西面海景，樓下即是叮叮車站。"},{id:120,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港麗駿酒店",question:"香港麗駿酒店 (Brighton Hotel Hong Kong)",options:["東區","灣仔區","中西區"],correctAnswer:1,explanation:"位於灣仔駱克道，緊鄰灣仔地鐵站出口，空間雖屬迷你精巧，但地理交通位置極佳。"},{id:121,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港華麗銅鑼灣酒店",question:"香港華麗銅鑼灣酒店 (Grand View Hotel Causeway Bay)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於銅鑼灣核心購物區旁，原屬華大集團旗下，提供高實用空間與經濟親民的客房價格。"},{id:122,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"香港東港島創意酒店",question:"香港東港島創意酒店 (The Shama Island North)",options:["東區","灣仔區","中西區"],correctAnswer:0,explanation:"位於北角，兼具精品酒店與服務式住宅概念，內部裝潢充滿北歐清新現代居家質感。"},{id:123,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"逸豪酒店",question:"逸豪酒店 (Haza Hotel Mongkok)",options:["深水埗區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於旺角新填地街，小型經濟城市連鎖，客房設計極簡實用，周邊街區港式本土氣息濃厚。"},{id:124,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角希爾頓花園酒店",question:"香港旺角希爾頓花園酒店 (Hilton Garden Inn)",options:["九龍城區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"位於旺角豉油街海旁側，希爾頓旗下經典輕奢品牌，頂樓設有景觀優美的露天泳池。"},{id:125,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港逸東酒店",question:"香港逸東酒店 (Eaton HK)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於佐敦彌敦道，融合王家衛式的港式霓虹美學，不定期舉辦本土多元藝術、環保藝術展演。"},{id:126,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"富薈炮台山酒店",question:"富薈炮台山酒店 (iclub Fortress Hill Hotel)",options:["灣仔區","東區","中西區"],correctAnswer:1,explanation:"富豪集團旗下富薈 (iclub) 經濟輕奢連鎖，主打全智能自助化入住、極簡科技與高性價比。"},{id:127,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"富薈灣仔酒店",question:"富薈灣仔酒店 (iclub Wan Chai Hotel)",options:["中西區","東區","灣仔區"],correctAnswer:2,explanation:"位於灣仔莊士敦道，主打綠色環保低碳概念，專為尋求便利交通與高效率的時尚商務旅客打造。"},{id:128,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"富薈上環酒店",question:"富薈上環酒店 (iclub Sheung Wan Hotel)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於上環文咸東街，鄰近中環金融中心與港澳碼頭，空間採全白極簡流線設計。"},{id:129,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"富薈旺角酒店",question:"富薈旺角酒店 (iclub Mong Kok Hotel)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於旺角晏架街，連通九龍西核心商業與購物帶，主打高挑空間、免費歐陸簡餐供應與全數位功能。"},{id:130,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"富薈土瓜灣酒店",question:"富薈土瓜灣酒店 (iclub To Kwa Wan Hotel)",options:["黃大仙區","觀塘區","九龍城區"],correctAnswer:2,explanation:"前稱富薈馬頭圍酒店，鄰近土瓜灣港鐵站，是該舊區活化後高CP值、環境新穎乾淨的連鎖好選擇。"},{id:131,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港晉逸精品酒店尖沙咀",question:"香港晉逸精品酒店．尖沙咀 (Butterfly on Prat TST)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀寶勒巷，主打色彩活潑的波普裝飾美學，深受來港逛街採購的女性與年輕背包客喜愛。"},{id:132,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀皇家太平洋酒店",question:"香港尖沙咀皇家太平洋酒店 (The Royal Pacific Hotel)",options:["中西區","油尖旺區","東區"],correctAnswer:1,explanation:"位於廣東道中港城上蓋，直接連通往返澳門與內地的客運碼頭，外觀採極具辨識度的耀眼金色玻璃設計。"},{id:133,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港華大盛品酒店",question:"香港華大盛品酒店 (Best Western Plus Hotel Hong Kong)",options:["東區","南區","中西區"],correctAnswer:2,explanation:"位於西營盤德輔道西，隸屬美國 Best Western 連鎖五星架構，房型實用經濟，適合長途與團體旅行。"},{id:134,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀百樂酒店",question:"香港尖沙咀百樂酒店 (Park Hotel Hong Kong)",options:["油尖旺區","灣仔區","大埔區"],correctAnswer:0,explanation:"位於尖沙咀金馬倫道，地處尖沙咀最熱鬧的餐飲與藥妝血拼帶中心點，自由行口碑老字號。"},{id:135,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"九龍維景酒店",question:"九龍維景酒店 (Metropark Hotel Kowloon)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於何文田窩打老道，香港中旅集團旗下老牌四星，大堂提供前往旺角和尖沙咀的免費穿梭巴士。"},{id:136,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"港島太平洋酒店",question:"港島太平洋酒店 (Island Pacific Hotel)",options:["東區","灣仔區","中西區"],correctAnswer:2,explanation:"位於西營盤海旁，採獨特圓弧形落地窗設計，拉開窗簾可眺望大面維多利亞港西側的日落與波光。"},{id:137,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港君怡酒店",question:"香港君怡酒店 (The Kimberley Hotel)",options:["油尖旺區","中西區","深水埗區"],correctAnswer:0,explanation:"位於尖沙咀金巴利道，設有經典的中餐廳君怡閣與咖啡廳，是日韓商務團體與觀光旅客極熱門的落腳點。"},{id:138,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港帝苑酒店",question:"香港帝苑酒店 (The Royal Garden)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖東，設有全港罕見的超大室內懸空地中海風格中庭。館內蝴蝶酥全港聞名，擁有多間頂級餐廳。"},{id:139,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港港青酒店",question:"香港港青酒店 (The Salisbury YMCA of Hong Kong)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀半島酒店正隔壁，雖由青年會(YMCA)營運，但規格達四星級，多數房間享有毫無遮擋的一線平價海景。"},{id:140,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港新樂酒店",question:"香港新樂酒店 (Shamrock Hotel)",options:["油尖旺區","東區","南區"],correctAnswer:0,explanation:"位於佐敦彌敦道，曾是李小龍等歷史名人最常光顧的傳奇老牌懷舊茶室與住宿地標（部分翻新活化）。"},{id:141,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港佐敦新境精品酒店",question:"香港佐敦新境精品酒店 (Jordan Comfort Inn)",options:["深水埗區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於廟街夜市旁，典型的港式精巧高CP值平價精品賓館，下樓就能體驗充滿鑊氣的地道大牌檔文化。"},{id:142,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港蘭桂坊酒店",question:"香港蘭桂坊酒店@九如坊 (Lan Kwai Fong Hotel)",options:["灣仔區","東區","中西區"],correctAnswer:2,explanation:"位於中環九如坊，設計巧妙地將精緻的東方絲綢古典風格、紅木雕刻融入當代時髦的西方精品旅宿概念中。"},{id:143,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角帝盛酒店",question:"香港旺角帝盛酒店 (Dorsett Mongkok Hong Kong)",options:["油尖旺區","荃灣區","葵青區"],correctAnswer:0,explanation:"位於大角咀，主打高科技無紙化入住，榮獲多項亞太區綠色環保酒店獎，並提供貼心的家庭親子套房。"},{id:144,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"香港城市花園酒店",question:"香港城市花園酒店 (City Garden Hotel)",options:["灣仔區","東區","九龍城區"],correctAnswer:1,explanation:"位於炮台山，緊鄰大型住宅花園，環境單純安靜，館內之粵菜廳「粵」曾榮獲米芝蓮一星評價。"},{id:145,section:"酒店/旅宿",sectionName:"度假親子",district:"大埔區",to:"香港大埔白鷺湖赤輝別墅",question:"香港大埔白鷺湖精品別墅 (Lake House Tai Po)",options:["沙田區","北區","大埔區"],correctAnswer:2,explanation:"位於大埔小白鷺湖互動中心旁，歐陸式純白水畔大宅，環境極度優美奢華，是遠離都市的隱密落腳點。"},{id:146,section:"酒店/旅宿",sectionName:"網紅海景",district:"中西區",to:"香港OneEightOne酒店",question:"香港 One-Eight-One 酒店 (One-Eight-One Hotel & Serviced Residences)",options:["中西區","東區","南區"],correctAnswer:0,explanation:"位於西環石塘咀，主打時尚現代的服務式住宅與酒店概念，客房擁有大面落地窗，直面震撼的維港西面海景。"},{id:147,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港中環奕居",question:"香港中環奕居 (The Upper House)",options:["灣仔區","中西區","油尖旺區"],correctAnswer:1,explanation:"位於金鐘太古廣場之上，由名師傅厚民打造，以極簡主義、大空間浴室以及極致私密的低調奢華聞名。"},{id:148,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"大嶼山長沙海邊小屋",question:"大嶼山長沙海邊度假屋 (Lower Cheung Sha Beach Houses)",options:["西貢區","荃灣區","離島區"],correctAnswer:2,explanation:"位於全港最長的水上活動聖地大嶼山長沙海灘旁，主打南非營火衝浪與極致放鬆的海島度假氛圍。"},{id:149,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"富豪東方酒店",question:"富豪東方酒店 (Regal Oriental Hotel)",options:["九龍城區","黃大仙區","觀塘區"],correctAnswer:0,explanation:"位於九龍城核心地帶，是見證舊啟德機場歷史的老牌四星酒店，周圍環繞傳統潮州菜與東南亞美食地圖。"},{id:150,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"尖沙咀香檳大廈精品賓館",question:"尖沙咀新興精品客棧 (TST Boutique Inn)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於尖沙咀金巴利道核心商圈，屬於典型的高CP值港式現代改裝精品賓館，下樓即可血拼各大小商場。"},{id:151,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"新浩景酒店",question:"新浩景酒店 (Grandview Hotel Mongkok)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:2,explanation:"位於旺角新填地街，鄰近朗豪坊，專門為精打細算的自由行散客提供簡約實用、生活機能發達的市中心落腳點。"},{id:152,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港木的地酒店",question:"香港木的地酒店．佐敦 (Madera Hong Kong)",options:["油尖旺區","深水埗區","九龍城區"],correctAnswer:0,explanation:"位於佐敦，完美融合當代藝術與西班牙式的熱情多彩設計，頂樓設有全景藝術酒吧，鬧中取靜。"},{id:153,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港雅逸酒店",question:"香港雅逸酒店 (Hotel lndigo Hong Kong Island)",options:["東區","灣仔區","中西區"],correctAnswer:1,explanation:"洲際旗下精品品牌，外牆有標誌性的金色巨龍鋁排設計，頂樓設有全港極著名的懸空玻璃底懸崖泳池。"},{id:154,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"香港晉逸精品酒店銅鑼灣",question:"香港晉逸精品酒店．銅鑼灣 (Butterfly on Morrison)",options:["南區","中西區","東區"],correctAnswer:2,explanation:"鄰近銅鑼灣及跑馬地，採用英倫復古精品美學與裝飾藝術，是一家性價比極高的歐洲風情時尚酒店。"},{id:155,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"翡格酒店",question:"翡格酒店 (The Figo)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環，是一家充滿木質調溫馨感、並且在香港自由行圈子中極具盛名的「寵物友善」精品設計酒店。"},{id:156,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港逸蘭精品酒店",question:"香港逸蘭精品酒店 (Lanson Place Causeway Bay)",options:["東區","油尖旺區","灣仔區"],correctAnswer:2,explanation:"位於銅鑼灣（行政分區屬灣仔），採優雅法式十九世紀建築風格，主打奢華低調的頂級酒店式公寓服務。"},{id:157,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"中環莎瑪服務式公寓",question:"中環莎瑪服務式公寓 (Shama Central Hong Kong)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環蘇豪區核心，專為高端商務長途客與國際自由行打造，居家機能一應俱全。"},{id:158,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"灣仔莎瑪服務式公寓",question:"灣仔莎瑪服務式公寓 (Shama Wanchai Hong Kong)",options:["東區","灣仔區","中西區"],correctAnswer:1,explanation:"位於灣仔核心商圈，鄰近港鐵站，採極簡現代北歐流線裝潢，商務出差極度便利。"},{id:159,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"尖沙咀莎瑪服務式公寓",question:"尖沙咀莎瑪服務式公寓 (Shama Tsim Sha Tsui)",options:["九龍城區","深水埗區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀彌敦道旁，下樓即是繁華的購物血拼區，客房兼具時髦現代感與溫馨居家機能。"},{id:160,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港朗廷酒店",question:"香港朗廷酒店 (The Langham Hong Kong)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀廣東道旁，充斥歐陸宮廷奢華風情，館內附設的唐閣為名揚海外的米芝蓮三星中餐廳。"},{id:161,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"九龍維景酒店",question:"九龍維景酒店 (Metropark Hotel Kowloon)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於何文田窩打老道，香港中旅集團旗下四星品牌，每天提供定時的免費穿梭巴士往返旺角與尖沙咀。"},{id:162,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"旺角維景酒店",question:"旺角維景酒店 (Metropark Hotel Mongkok)",options:["深水埗區","黃大仙區","油尖旺區"],correctAnswer:2,explanation:"位於太子港鐵站出口旁，直通跨境巴士站，對於從廣東深圳或內地深夜抵港的旅客而言交通第一便利。"},{id:163,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"銅鑼灣維景酒店",question:"銅鑼灣維景酒店 (Metropark Hotel Causeway Bay)",options:["中西區","灣仔區","東區"],correctAnswer:1,explanation:"位於天后站旁（行政分區屬中西區營運），大面客房窗戶直面維多利亞公園及維港東面海景。"},{id:164,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港港青酒店",question:"香港港青酒店 (The Salisbury YMCA)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀梳士巴利道，半島酒店正隔壁。雖由 YMCA 經營，但客房設備與無遮擋海景直逼五星水準。"},{id:165,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港百樂酒店",question:"香港百樂酒店 (Park Hotel Hong Kong)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖沙咀金馬倫道，坐落於九龍最密集的餐飲老街與美妝店核心帶，是港澳自由行口碑老牌。"},{id:166,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港金域假日酒店",question:"香港金域假日酒店 (Holiday Inn Golden Mile)",options:["深水埗區","黃大仙區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀彌敦道黃金地段，地鐵站一出即達，以寬敞的家庭雙床房型及貼心的兒童友善政策聞名。"},{id:167,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港華麗酒店",question:"香港華麗酒店 (Best Western Grand Hotel)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀柯士甸路，美式 Best Western 旗下連鎖，客房採經典挑高歐陸裝潢，價格大眾經濟。"},{id:168,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港華麗海景酒店",question:"香港華麗海景酒店 (Best Western Hotel Harbour View)",options:["東區","中西區","南區"],correctAnswer:1,explanation:"位於西營盤，頂樓設有全景露天泳池，能以極其親民平價的預算解鎖維多利亞港西側海景。"},{id:169,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港華大盛品酒店",question:"香港華大盛品酒店 (Best Western Plus Hotel)",options:["灣仔區","東區","中西區"],correctAnswer:2,explanation:"位於西環水街旁，標準的美式商務連鎖四星，客房實用率極高，深得國際團體與長途客信賴。"},{id:170,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"美麗華酒店",question:"美麗華酒店 (The Mira Hong Kong)",options:["油尖旺區","中西區","深水埗區"],correctAnswer:0,explanation:"位於尖沙咀彌敦道，直通美麗華廣場，設計主打時尚、前衛與極簡數位科技風，深受年輕潮人追捧。"},{id:171,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"問月酒店",question:"問月酒店 (Mira Moon)",options:["東區","油尖旺區","灣仔區"],correctAnswer:1,explanation:"美麗華集團旗下精品設計酒店，位於銅鑼灣，室內設計大膽融合中國傳統「中秋奔月」與現代前衛美學。"},{id:172,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港帝苑酒店",question:"香港帝苑酒店 (The Royal Garden)",options:["九龍城區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"位於尖東，設有東亞罕見的超大型11層高懸空室內花園中庭，館內之「蝴蝶酥」為全港第一伴手禮名產。"},{id:173,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港君怡酒店",question:"香港君怡酒店 (The Kimberley Hotel)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀金巴利道，地理位置優越，擁有多間老牌高水準中粵餐廳，是星馬日韓團客最愛地標。"},{id:174,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港皇家太平洋酒店",question:"香港皇家太平洋酒店 (The Royal Pacific)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"坐落於尖沙咀廣東道中港城商場之上，大樓採標誌性土豪金玻璃幕牆，直通中港客運碼頭，交通樞紐地位無敵。"},{id:175,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港恆豐酒店",question:"香港恆豐酒店 (Prudential Hotel)",options:["黃大仙區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"位於佐敦彌敦道黃金中軸線上，直接連通佐敦地鐵站出口與恆豐中心商場，下樓就能體驗極致便利的香港夜生活。"},{id:176,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"龍堡國際",question:"龍堡國際 (B P International)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"緊鄰尖沙咀九龍公園與柯士甸地鐵站，客房視野完全開揚，直面城市綠肺景致，性價比在尖沙咀區難逢敵手。"},{id:177,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港南洋酒店",question:"香港南洋酒店 (South Pacific Hotel)",options:["東區","灣仔區","南區"],correctAnswer:1,explanation:"位於銅鑼灣摩理臣山道，採獨特的圓柱形玻璃外觀建築設計，步行數分鐘即達時代廣場，鬧區機能成熟。"},{id:178,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港逸東酒店",question:"香港逸東酒店 (Eaton HK)",options:["深水埗區","九龍城區","油尖旺區"],correctAnswer:2,explanation:"位於佐敦，巧妙融入大膽復古的八十年代港式霓虹美學，是一家強烈倡導環保與多元包容社區文化的前衛藝術酒店。"},{id:179,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港康得思酒店",question:"香港康得思酒店 (Cordis Hong Kong)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於旺角中心點，直接連通朗豪坊大型購物商場與旺角地鐵站，頂樓設有高空天際露天泳池與「川」水療中心。"},{id:180,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"帝京酒店",question:"帝京酒店 (Royal Plaza Hotel)",options:["沙田區","油尖旺區","西貢區"],correctAnswer:1,explanation:"位於旺角東站上蓋，有無縫連通的大型購物商場 MOKO。客房空間之大在九龍市區極具競爭力，往返內地東鐵線首選。"},{id:181,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"城景國際",question:"城景國際 (The Cityview)",options:["九龍城區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"位於油麻地港鐵站旁，由中華基督教青年會營運，主打四星級綠色低碳節能概念、優質餐飲與極度發達的交通位置。"},{id:182,section:"酒店/旅宿",sectionName:"度假親子",district:"深水埗區",to:"YHA美荷樓青年旅舍",question:"YHA 美荷樓青年旅舍",options:["深水埗區","黃大仙區","九龍城區"],correctAnswer:0,explanation:"位於石硤尾，由香港二級歷史建築（早期公屋徙置大廈地標）活化改建而成，內設美荷樓舊時生活紀念館。"},{id:183,section:"酒店/旅宿",sectionName:"度假親子",district:"沙田區",to:"帝逸酒店",question:"帝逸酒店 (ALVA HOTEL BY ROYAL)",options:["北區","沙田區","大埔區"],correctAnswer:1,explanation:"位於沙田城門河畔，新鴻基旗下新一代時尚輕奢度假地標，免費租借單車，頂樓有無邊際高空泳池。"},{id:184,section:"酒店/旅宿",sectionName:"度假親子",district:"沙田區",to:"香港沙田凱悅酒店",question:"香港沙田凱悅酒店 (Hyatt Regency Sha Tin)",options:["西貢區","元朗區","沙田區"],correctAnswer:2,explanation:"依山傍水緊鄰香港中文大學與東鐵線大學站，遠離九龍都市喧囂，綠意環繞，充滿美式山水城市度假感。"},{id:185,section:"酒店/旅宿",sectionName:"度假親子",district:"沙田區",to:"香港麗豪酒店",question:"香港麗豪酒店 (Regal Riverside Hotel)",options:["沙田區","大埔區","北區"],correctAnswer:0,explanation:"位於沙田大涌橋路城門河畔，客房量巨大，館內設有多間不同風味的異國餐廳，主打經濟大眾型高CP值度假。"},{id:186,section:"酒店/旅宿",sectionName:"度假親子",district:"西貢區",to:"WM酒店",question:"WM 酒店 (WM Hotel)",options:["觀塘區","西貢區","黃大仙區"],correctAnswer:1,explanation:"坐落於有「香港後花園」美譽的西貢海濱海邊，純白幾何教堂與矮木屋設計，擁有濃厚的東南亞海島頂級度假村風情。"},{id:187,section:"酒店/旅宿",sectionName:"度假親子",district:"西貢區",to:"香港九龍東皇冠假日酒店",question:"香港九龍東皇冠假日酒店 (Crowne Plaza Hong Kong Kowloon East)",options:["觀塘區","九龍城區","西貢區"],correctAnswer:2,explanation:"位於將軍澳港鐵站及 PopCorn 大型商場上蓋，行政分區劃歸西貢，頂樓設有視野極其震撼的星空露天酒吧。"},{id:188,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"悅來酒店",question:"悅來酒店 (Panda Hotel)",options:["荃灣區","葵青區","屯門區"],correctAnswer:0,explanation:"荃灣核心地標、因外牆巨大熊貓塗鴉而被市民暱稱為「熊貓酒店」，房間基數大、周邊荃華街美食機能極其完善。"},{id:189,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"帝景酒店",question:"帝景酒店 (Royal View Hotel)",options:["離島區","荃灣區","南區"],correctAnswer:1,explanation:"位於汀九青山公路海旁，依山傍海而建，拉開客房窗簾即可將氣勢磅礡的青馬大橋與汀九橋夜景一覽無遺。"},{id:190,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"荃灣西如心酒店",question:"荃灣西如心酒店 (Nina Hotel Tsuen Wan West)",options:["葵青區","屯門區","荃灣區"],correctAnswer:2,explanation:"華懋集團旗下地標性雙子塔建築，全港客房總量前三的巨型五星酒店，完美俯瞰藍巴勒海峽與昂船洲大橋。"},{id:191,section:"酒店/旅宿",sectionName:"頂級奢華",district:"油尖旺區",to:"香港麗晶酒店",question:"香港麗晶酒店 (Regent Hong Kong)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀梳士巴利道海旁，由洲際酒店斥巨資傳奇蛻變回歸，坐擁極致的維港一線煙花海景與多間米芝蓮頂級餐廳。"},{id:192,section:"酒店/旅宿",sectionName:"網紅海景",district:"北區",to:"沙頭角海景別墅",question:"沙頭角海景別墅精品民宿 (Sha Tau Kok Seaview Villa)",options:["大埔區","北區","元朗區"],correctAnswer:1,explanation:"位於新界北區沙頭角禁區逐步開放後的新興秘境，主打遠離都市喧囂的客家鄉郊情懷與印洲塘平靜海景。"},{id:193,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"長洲西園",question:"長洲西園 (Saiyuen Camping Adventure Park)",options:["西貢區","南區","離島區"],correctAnswer:2,explanation:"位於長洲西南角，全港極具指標性的特色星空帳篷與豪華印第安營火 Glamping（奢華露營）戶外度假基地。"},{id:194,section:"酒店/旅宿",sectionName:"度假親子",district:"葵青區",to:"香港永倫800酒店",question:"香港永倫 800 酒店 (Winland 800 Hotel)",options:["葵青區","荃灣區","屯門區"],correctAnswer:0,explanation:"前稱為盛逸酒店，位於青衣藍巴勒海峽旁，房型實用，擁有超巨型露天東南亞度假風情園林泳池。"},{id:195,section:"酒店/旅宿",sectionName:"度假親子",district:"屯門區",to:"香港黃金海岸酒店",question:"香港黃金海岸酒店 (Hong Kong Gold Coast Hotel)",options:["元朗區","屯門區","荃灣區"],correctAnswer:1,explanation:"位於屯門青山公路，緊鄰黃金泳灘，主打各式夢幻兒童主題房、全港首屈一指的親子遊樂設施與海濱度假村氛圍。"},{id:196,section:"酒店/旅宿",sectionName:"度假親子",district:"元朗區",to:"香港天水圍悅品天秀酒店",question:"香港悅品天秀酒店．元朗 (Hotel COZI Wetland)",options:["北區","大埔區","元朗區"],correctAnswer:2,explanation:"位於天水圍，緊鄰香港濕地公園，客房採活潑溫馨的小鳥與大自然主題設計，特別適合家庭親子客生態遊落腳。"},{id:197,section:"酒店/旅宿",sectionName:"度假親子",district:"屯門區",to:"悅品度假酒店屯門",question:"悅品度假酒店．屯門 (Hotel COZI Resort Tuen Mun)",options:["屯門區","元朗區","葵青區"],correctAnswer:0,explanation:"由舊工廈活化改建，鄰近屯門港鐵站，內部大膽打造希臘、日本、泰國等環球各國風情主題客房與兒童賽車場。"},{id:198,section:"酒店/旅宿",sectionName:"度假親子",district:"葵青區",to:"悅品酒店荃灣",question:"悅品酒店．荃灣 (Hotel COZI Oasis Tsuen Wan)",options:["荃灣區","葵青區","深水埗區"],correctAnswer:1,explanation:"行政分區屬於葵青區（鄰近大窩口站），內部裝潢採高雅的都會綠洲現代風，生活機能安靜且高性價比。"},{id:199,section:"酒店/旅宿",sectionName:"度假親子",district:"觀塘區",to:"悅品海景酒店觀塘",question:"悅品海景酒店．觀塘 (Hotel COZI Harbourview)",options:["九龍城區","黃大仙區","觀塘區"],correctAnswer:2,explanation:"位於觀塘偉業街，前稱為君立酒店/旭逸酒店，高層部分客房能遠眺啟德郵輪碼頭與東九龍全新維港海景。"},{id:200,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港朗廷酒店",question:"香港朗廷酒店 (The Langham Hong Kong)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀廣東道購物核心帶，散發十九世紀倫敦經典皇室宮廷奢華感，館內的唐閣為世界知名的米芝蓮三星中餐廳。"},{id:201,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港海景嘉福洲際酒店",question:"香港海景嘉福洲際酒店 (InterContinental Grand Stanford)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖東么地道海旁，老牌國際頂級五星，客房保養極佳且視野開揚，館內之海景軒中餐廳口碑載道。"},{id:202,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港中環石板街酒店",question:"香港中環石板街酒店 (The Pottinger Hong Kong)",options:["灣仔區","東區","中西區"],correctAnswer:2,explanation:"坐落於中環一級歷史建築「砵典乍街」（石板街）旁，完美的英倫優雅復古與現代精品美學交融設計。"},{id:203,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港奧林匹克酒店",question:"香港奧林匹克酒店 (The Olympian Hong Kong)",options:["中西區","油尖旺區","深水埗區"],correctAnswer:0,explanation:"位於大角咀海旁（行政分區劃歸中西區營運），主打超高挑高空間、極低調私密且精緻奢華的精品豪宅風格。"},{id:204,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"北角海逸酒店",question:"北角海逸酒店 (Harbour Plaza North Point)",options:["灣仔區","東區","觀塘區"],correctAnswer:1,explanation:"位於北角英皇道，長江實業旗下海逸連鎖品牌，設有25米長戶外露天泳池，是東區極具性價比的商務四星地標。"},{id:205,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"土瓜灣旭逸酒店",question:"土瓜灣旭逸酒店 (Hotel Ease Access To Kwa Wan)",options:["黃大仙區","九龍城區","觀塘區"],correctAnswer:1,explanation:"鄰近土瓜灣港鐵站，主打明快輕工业美學流線設計，為精打細算的自由行旅客提供高效率、乾淨乾爽的優質客房。"},{id:206,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港麥當勞道貳號",question:"香港麥當勞道貳號 (Two MacDonnell Road)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中半山高尚住宅區，環繞半山綠意，遠眺中環天際線，屬於逸蘭 (Lanson Place) 旗下的高隱密性精緻公寓式酒店。"},{id:207,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港港島英迪格酒店",question:"香港港島英迪格酒店 (Hotel Indigo Hong Kong Island)",options:["東區","灣仔區","中西區"],correctAnswer:1,explanation:"洲際旗下高端精品品牌，外牆飾有醒目的金色巨龍鋁板，頂樓著名的「懸空玻璃底泳池」是風靡全網的拍照打卡點。"},{id:208,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港基督教青年會賓館",question:"香港基督教青年會賓館 (YMCA International House)",options:["深水埗區","黃大仙區","油尖旺區"],correctAnswer:2,explanation:"位於油麻地窩打老道，地鐵站出站即達，客房採溫馨簡約的實用功能裝潢，深受全球學生與背包客歡迎。"},{id:209,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港芬名酒店",question:"香港芬名酒店 (The Fleming Hong Kong)",options:["灣仔區","東區","中西區"],correctAnswer:0,explanation:"位於灣仔核心區，室內設計巧妙致敬香港標誌性的「天星小輪」，將濃郁的復古黃銅、墨綠森林色調與工業美學完美融合。"},{id:210,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港九如坊蘭桂坊酒店",question:"香港蘭桂坊酒店@九如坊 (Lan Kwai Fong Hotel@Kau U Fong)",options:["灣仔區","中西區","東區"],correctAnswer:1,explanation:"位於中環九如坊，巧妙將傳統中式絲綢、紅木雕刻融入西方摩登現代設計中，曾多次榮獲亞洲最佳精品酒店獎項。"},{id:211,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"尖沙咀極致精品酒店",question:"尖沙咀極致精品客棧 (TST Zen Boutique Inn)",options:["九龍城區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀海防道商圈，屬於典型港式高質感翻新精品旅館，下樓步行一分鐘即達尖沙咀地鐵站與九龍公園。"},{id:212,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角智選假日酒店",question:"香港旺角智選假日酒店 (Holiday Inn Express Hong Kong Mongkok)",options:["油尖旺區","深水埗區","九龍城區"],correctAnswer:0,explanation:"位於旺角登打士街，洲際旗下優質連鎖，主打免費智慧早餐、高實用精巧空間與極致高效的商務旅行體驗。"},{id:213,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港銅鑼灣智選假日酒店",question:"香港銅鑼灣智選假日酒店 (Holiday Inn Express Causeway Bay)",options:["東區","灣仔區","中西區"],correctAnswer:1,explanation:"位於銅鑼灣霎東街，緊鄰時代廣場及地鐵出口，是來港進行高強度購物血拼自由行旅客的極熱門平價首選。"},{id:214,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港上環海景智選假日酒店",question:"香港上環海景智選假日酒店 (Holiday Inn Express Hong Kong SoHo)",options:["東區","南區","中西區"],correctAnswer:2,explanation:"位於上環蘇豪區邊緣，主打環保低碳認證設計，部分高層客房能無遮擋欣賞到維多利亞港西側海景。"},{id:215,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港木的地酒店中環",question:"香港木的地酒店．中環 (Madera Hollywood)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環荷李活道，室內牆面畫有荷里活巨星瑪麗蓮夢露等經典壁畫，主打奢華好萊塢復古風情公寓房型。"},{id:216,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"晉逸精品酒店中環",question:"晉逸精品酒店．中環 (Butterfly on Wellington)",options:["灣仔區","油尖旺區","中西區"],correctAnswer:1,explanation:"位於中環威靈頓街（行政管理屬九龍總部），緊鄰蘭桂坊，室內充滿濃郁的東方新古典精品設計美學。"},{id:217,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"晉逸精品酒店銅鑼灣",question:"晉逸精品酒店．銅鑼灣 (Butterfly on Morrison)",options:["灣仔區","南區","東區"],correctAnswer:2,explanation:"位於銅鑼灣摩理臣山道（行政分區屬東區營運），融合歐陸英倫古典風與摩登時尚，步行即達天后及銅鑼灣鬧區。"},{id:218,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港宜必思中上環酒店",question:"宜必思香港中上環酒店 (Ibis Hong Kong Central & Sheung Wan)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環德輔道西，色彩明快活潑，高層面海房擁有極高CP值的維港西岸美景，樓下即是百年叮叮車站。"},{id:219,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"宜必思香港北角酒店",question:"宜必思香港北角酒店 (Ibis Hong Kong North Point)",options:["東區","灣仔區","中西區"],correctAnswer:1,explanation:"位於北角渣華道（由灣仔分部管理），緊鄰北角地鐵站及北角碼頭，以極致經濟實惠的房價與優越交通聞名。"},{id:220,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港灣仔帝盛酒店",question:"香港灣仔帝盛酒店 (Dorsett Wanchai Hong Kong)",options:["中西區","東區","灣仔區"],correctAnswer:2,explanation:"位於灣仔皇后大道東，鄰近跑馬地馬場，館內提供多款趣味親子家庭主題房，並有免費穿梭巴士往返中環。"},{id:221,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角帝盛酒店",question:"香港旺角帝盛酒店 (Dorsett Mongkok Hong Kong)",options:["油尖旺區","深水埗區","九龍城區"],correctAnswer:0,explanation:"位於大角咀，曾榮獲多項亞太區綠色環保酒店獎項，主打全智能全數位化入住、高CP值與貼心的家庭房設計。"},{id:222,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"香港啟德帝盛酒店",question:"香港啟德帝盛酒店 (Dorsett Kai Tak)",options:["東區","九龍城區","觀塘區"],correctAnswer:1,explanation:"鄰近全新啟德體育園與啟德舊跑道發展區，設計充滿活力現代感，坐擁東九龍全新開揚維港海景。"},{id:223,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"香港荃灣帝盛酒店",question:"香港荃灣帝盛酒店 (Dorsett Tsuen Wan Hong Kong)",options:["葵青區","屯門區","荃灣區"],correctAnswer:2,explanation:"位於葵涌健全街（行政分區劃歸荃灣），設有大型兒童遊樂區及戶外泳池，提供極其親民超值的度假套房。"},{id:224,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀百樂酒店",question:"香港尖沙咀百樂酒店 (Park Hotel Hong Kong)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀金馬倫道核心重鎮，周邊環繞九龍最密集的港式美食街與各大小藥妝購物商場，自由行口碑老牌。"},{id:225,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港君怡酒店",question:"香港君怡酒店 (The Kimberley Hotel)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀金巴利道，交通與生活機能極度發達，館內君怡閣中餐廳頗負盛名，是星馬日韓觀光團熱門落腳點。"},{id:226,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港帝苑酒店",question:"香港帝苑酒店 (The Royal Garden)",options:["沙田區","九龍城區","油尖旺區"],correctAnswer:2,explanation:"位於尖東，設有全港罕見的超大室內懸空地中海風格花園中庭。館內頂級粵菜、地道日料林立，蝴蝶酥全港聞名。"},{id:227,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港港青酒店",question:"香港港青酒店 (The Salisbury YMCA of Hong Kong)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀半島酒店正隔壁，雖由青年會營運，但規格達四星級，多數房間享有毫無遮擋的一線高性價比海景。"},{id:228,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港皇家太平洋酒店",question:"香港皇家太平洋酒店 (The Royal Pacific Hotel)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於廣東道中港城上蓋，外觀採耀眼的金黃色玻璃幕牆設計，直接連通往返澳門與內地的客運碼頭，地利無敵。"},{id:229,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港恆豐酒店",question:"香港恆豐酒店 (Prudential Hotel)",options:["黃大仙區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"位於佐敦彌敦道上蓋，直通佐敦地鐵站與恆豐中心商場，下樓即是油尖旺核心夜生活圈，生活機能無懈可擊。"},{id:230,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"龍堡國際",question:"龍堡國際 (B P International)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"緊鄰尖沙咀九龍公園與柯士甸站，大面客房視野直面翠綠的公園森林或遠眺維港，高實用率且性價比極高。"},{id:231,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港南洋酒店",question:"香港南洋酒店 (South Pacific Hotel)",options:["東區","灣仔區","南區"],correctAnswer:1,explanation:"位於銅鑼灣與灣仔交界，採獨特的標誌性圓柱形玻璃幕牆建築，步行數分鐘即可解鎖時代廣場購物圈。"},{id:232,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港逸東酒店",question:"香港逸東酒店 (Eaton HK)",options:["九龍城區","深水埗區","油尖旺區"],correctAnswer:2,explanation:"位於佐敦，融合王家衛式的懷舊復古港式霓虹美學，不定期舉辦本土多元藝術、環保展演，充滿前衛文青氣息。"},{id:233,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港城景國際",question:"香港城景國際 (The Cityview Hong Kong)",options:["中西區","黃大仙區","油尖旺區"],correctAnswer:2,explanation:"位於油麻地窩打老道，由中華基督教青年會管理（行政營運屬中西區分部），主打四星級綠色低碳節能概念與發達交通。"},{id:234,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"仕德福山景酒店",question:"仕德福山景酒店 (Stanford Hillview Hotel)",options:["油尖旺區","九龍城區","觀塘區"],correctAnswer:0,explanation:"隱密坐落於尖沙咀天文台山丘之上，鬧中取靜且環境清幽，下山步行一分鐘即達熱鬧喧囂的諾士佛台酒吧街。"},{id:235,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"仕德福酒店",question:"仕德福酒店 (Stanford Hotel)",options:["深水埗區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於旺角核心的豉油街，下樓就是熱鬧的女人街、波鞋街與潮流商場，是精打細算、主攻血拼的自由行散客愛店。"},{id:236,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港四季酒店",question:"香港四季酒店 (Four Seasons Hotel Hong Kong)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:0,explanation:"位於中環金融街，直通IFC商場，坐擁維港一線海景，館內擁有多間榮獲米芝蓮星級肯定的頂級餐廳與世界級水療中心。"},{id:237,section:"酒店/旅宿",sectionName:"網紅海景",district:"東區",to:"香港歷山酒店",question:"香港歷山酒店 (Hotel Alexandra)",options:["灣仔區","東區","觀塘區"],correctAnswer:1,explanation:"位於北角海旁，設計大膽揉合維多利亞宮廷奢華風與現代時尚，金碧輝煌的大堂與精緻海景客房是社交媒體熱門打卡點。"},{id:238,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"富豪機場酒店",question:"富豪機場酒店 (Regal Airport Hotel)",options:["荃灣區","葵青區","離島區"],correctAnswer:2,explanation:"位於赤鱲角香港國際機場，設有行人通道無縫連接客運大樓，主打世界級的中轉商務商務機能與完善的室內外泳池設施。"},{id:239,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"香港大嶼山寶蓮禪寺客堂",question:"大嶼山昂坪寶蓮禪寺客堂 (Po Lin Monastery Guest House)",options:["離島區","西貢區","北區"],correctAnswer:0,explanation:"位於昂坪高原，緊鄰天壇大佛，提供尋求心靈平靜的旅客及信眾體驗暮鼓晨鐘、品嚐精緻齋菜的獨特清幽宿處。"},{id:240,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港港威酒店",question:"香港港威酒店 (Gateway Hotel, Marco Polo)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀廣東道海港城內，馬哥孛羅酒店集團旗下，主打時尚、現代、朝氣蓬勃的設計概念與無與倫比的購物便利性。"},{id:241,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港太子酒店",question:"香港太子酒店 (Prince Hotel, Marco Polo)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:2,explanation:"坐落於尖沙咀海港城西北端，近年經過全面時尚翻新，以亮麗活潑的色彩點綴現代空間，深得親子與自由行血拼族喜愛。"},{id:242,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港中環福諾特酒店",question:"香港中環福諾特酒店 (The Forenax Hotel Central)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環核心商圈的上坡街道，精緻小巧的輕奢公寓式精品設計，為注重私密性與科技生活感的商務自由行打造。"},{id:243,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港英皇駿景酒店",question:"香港英皇駿景酒店 (The Emperor Hotel)",options:["東區","灣仔區","南區"],correctAnswer:1,explanation:"位於灣仔皇后大道東，鄰近跑馬地馬場，由名師打造摩登現代空間，館內粵菜廳駿景軒曾連續多年榮獲米芝蓮星級榮譽。"},{id:244,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"香港晉逸精品酒店中環",question:"香港晉逸精品酒店．中環 (Butterfly on Wellington)",options:["灣仔區","中西區","東區"],correctAnswer:1,explanation:"雖然名為中環，但在行政與品牌連鎖營運上極具代表性。客房內飾充滿東方傳統新古典精品美學，步行可至中環蘇豪區。"},{id:245,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港海景絲麗酒店",question:"香港海景絲麗酒店 (Silka Seaview Hotel)",options:["深水埗區","九龍城區","油尖旺區"],correctAnswer:2,explanation:"位於油麻地上海街，鄰近廟街夜市，帝盛酒店集團旗下經濟型連鎖品牌，以超高性價比、實用乾淨的客房著稱。"},{id:246,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港遠東絲麗酒店",question:"香港遠東絲麗酒店 (Silka Far East Hotel)",options:["荃灣區","葵青區","油尖旺區"],correctAnswer:2,explanation:"隸屬絲麗連鎖架構（由油尖旺核心辦公室管理），客房經濟實惠，專為追求高交通機動性與精簡预算的商務背包客打造。"},{id:247,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港灣仔旭逸酒店",question:"香港灣仔旭逸酒店 (Hotel Ease Access Wan Chai)",options:["灣仔區","東區","中西區"],correctAnswer:0,explanation:"位於灣仔駱克道，緊鄰灣仔與銅鑼灣商圈，全館採溫馨亮麗的木質調流線設計，提供高效率的都市型落腳體驗。"},{id:248,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"香港啟德旭逸酒店",question:"香港啟德旭逸酒店 (Hotel Ease Access Kai Tak)",options:["黃大仙區","九龍城區","觀塘區"],correctAnswer:1,explanation:"位於新蒲崗邊緣，鄰近全新啟德發展區，由舊工廈成功活化而成，充滿現代工業風設計感，性價比極高。"},{id:249,section:"酒店/旅宿",sectionName:"度假親子",district:"觀塘區",to:"香港觀塘帝盛酒店",question:"香港觀塘帝盛酒店 (Dorsett Singapore/Kwun Tong Hong Kong)",options:["九龍城區","黃大仙區","觀塘區"],correctAnswer:2,explanation:"位於觀塘鴻圖道，地處東九龍核心商貿區，內部裝潢兼具時尚與現代商務質感，深受亞太商務出差客青睞。"},{id:250,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港金域假日酒店",question:"香港金域假日酒店 (Holiday Inn Golden Mile)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀彌敦道黃金地段，地鐵站出入口即在身旁，以極其寬敞的雙床家庭房及友善的兒童免費入住政策聞名。"},{id:251,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀凱悅酒店",question:"香港尖沙咀凱悅酒店 (Hyatt Regency Hong Kong, Tsim Sha Tsui)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"坐落於尖沙咀河內道K11購物藝術館上蓋，直通港鐵站，高層客房可俯瞰維港美景，館內的凱悅軒粵菜十分地道。"},{id:252,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港JW萬豪酒店",question:"香港 JW 萬豪酒店 (JW Marriott Hotel Hong Kong)",options:["灣仔區","東區","中西區"],correctAnswer:2,explanation:"位於金鐘太古廣場上蓋，交通樞紐核心，客房裝潢高雅大氣，配備大面景觀窗，多年來維持極高水準的頂級五星服務。"},{id:253,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港港島香格里拉大酒店",question:"香港港島香格里拉大酒店 (Island Shangri-La)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於金鐘太古廣場之上，館內中庭懸掛著巨幅亞洲最大室內山水絹畫《尋源圖》，散發極致尊貴的東方傳奇奢華氣韻。"},{id:254,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港港麗酒店",question:"香港港麗酒店 (Conrad Hong Kong)",options:["東區","灣仔區","中西區"],correctAnswer:1,explanation:"希爾頓集團旗下頂級奢華品牌，位於金鐘商圈（行政分區劃歸灣仔區），客房設計典雅，享有高空維港與太平山雙重極致美景。"},{id:255,section:"酒店/旅宿",sectionName:"度假親子",district:"南區",to:"香港海洋公園萬豪酒店",question:"香港海洋公園萬豪酒店 (Hong Kong Ocean Park Marriott Hotel)",options:["中西區","東區","南區"],correctAnswer:2,explanation:"緊鄰香港海洋公園正門，大堂內設有高達16米的大型圓柱形水族館，客房採海洋與綠意主題設計，是全港一線的親子度假勝地。"},{id:256,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港朗廷酒店",question:"香港朗廷酒店 (The Langham Hong Kong)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀廣東道購物中軸，散發著英式古典皇室宮廷奢華感，館內的三星米芝蓮中餐廳「唐閣」名揚海內外。"},{id:257,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港海景嘉福洲際酒店",question:"香港海景嘉福洲際酒店 (InterContinental Grand Stanford)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖東麼地道海旁，經典國際頂級五星，高層維港海景房開揚大氣，館內粵菜名店「海景軒」口碑極佳。"},{id:258,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港中環石板街酒店",question:"香港中環石板街酒店 (The Pottinger Hong Kong)",options:["灣仔區","東區","中西區"],correctAnswer:2,explanation:"坐落於歷史悠久的一級古蹟「砵典乍街」旁，外觀及內部巧妙融合歐陸復古老香港情懷與現代頂級精品美學。"},{id:259,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港奧林匹克酒店",question:"香港奧林匹克酒店 (The Olympian Hong Kong)",options:["中西區","油尖旺區","深水埗區"],correctAnswer:0,explanation:"位於大角咀海旁（行政營運屬中西區分部），主打極高挑高空間、低調奢華的精品私密豪宅風格客房。"},{id:260,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"北角海逸酒店",question:"北角海逸酒店 (Harbour Plaza North Point)",options:["灣仔區","東區","觀塘區"],correctAnswer:1,explanation:"位於北角英皇道，長江實業旗下海逸品牌，附設25米長戶外露天泳池，是港島東區極具性價比的舒適型商務四星。"},{id:261,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"土瓜灣旭逸酒店",question:"土瓜灣旭逸酒店 (Hotel Ease Access To Kwa Wan)",options:["黃大仙區","九龍城區","觀塘區"],correctAnswer:1,explanation:"鄰近土瓜灣港鐵站，主打明快簡約的工業線條美學，為注重高效率、乾淨舒適的自由行散客提供親民客房。"},{id:262,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港麥當勞道貳號",question:"香港麥當勞道貳號 (Two MacDonnell Road)",options:["灣仔區","南區","中西區"],correctAnswer:2,explanation:"位於中半山高尚住宅區，環繞半山綠意，俯瞰中環天際線，屬於逸蘭集團旗下的高隱密性長短途精緻公寓式酒店。"},{id:263,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港港島英迪格酒店",question:"香港港島英迪格酒店 (Hotel Indigo Hong Kong Island)",options:["灣仔區","東區","中西區"],correctAnswer:0,explanation:"洲際旗下精品設計品牌，外牆飾有耀眼的金色巨龍鋁板，頂樓極具代表性的「懸空玻璃底泳池」是風靡網路的打卡熱點。"},{id:264,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港基督教青年會賓館",question:"香港基督教青年會賓館 (YMCA International House)",options:["深水埗區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於油麻地窩打老道，地鐵站出站即達，客房裝潢溫馨實用且生活機能發達，深受全球學生與國際背包客喜愛。"},{id:265,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港芬名酒店",question:"香港芬名酒店 (The Fleming Hong Kong)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔核心區，室內設計巧妙向香港標誌性的「天星小輪」致敬，將復古黃銅、墨綠色調與經典老香港工業風完美融合。"},{id:266,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港九如坊蘭桂坊酒店",question:"香港蘭桂坊酒店@九如坊 (Lan Kwai Fong Hotel@Kau U Fong)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環九如坊，將經典的中式絲綢紋理與紅木雕刻完美揉合於現代西方精品旅宿概念中，獲獎無數。"},{id:267,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"尖沙咀極致精品酒店",question:"尖沙咀極致精品客棧 (TST Zen Boutique Inn)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖沙咀海防道核心帶，典型的精緻翻新精品旅館，步行一分鐘即達地鐵站出口與九龍公園，機能全面。"},{id:268,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角智選假日酒店",question:"香港旺角智選假日酒店 (Holiday Inn Express Hong Kong Mongkok)",options:["深水埗區","九龍城區","油尖旺區"],correctAnswer:2,explanation:"位於旺角登打士街，洲際旗下優質商務連鎖，主打便捷的智慧早餐、高效精巧的客房空間與極高的實用便利性。"},{id:269,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港銅鑼灣智選假日酒店",question:"香港銅鑼灣智選假日酒店 (Holiday Inn Express Causeway Bay)",options:["灣仔區","東區","中西區"],correctAnswer:0,explanation:"位於銅鑼灣霎東街，緊鄰時代廣場及地鐵出口，是專程來港進行高強度購物採購的自由行客群之平價熱點。"},{id:270,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港上環海景智選假日酒店",question:"香港上環海景智選假日酒店 (Holiday Inn Express Hong Kong SoHo)",options:["東區","中西區","南區"],correctAnswer:1,explanation:"位於上環蘇豪區旁，主打低碳認證綠色建築設計，高層部分客房能無遮擋欣賞到維多利亞港西側海景。"},{id:271,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港木的地酒店中環",question:"香港木的地酒店．中環 (Madera Hollywood)",options:["灣仔區","東區","中西區"],correctAnswer:2,explanation:"位於中環荷李活道，外牆與室內飾有精美的好萊塢巨星壁畫，主打好萊塢復古奢華風情的高質感大空間套房。"},{id:272,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"晉逸精品酒店中環",question:"晉逸精品酒店．中環 (Butterfly on Wellington)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環威靈頓街，鄰近蘭桂坊，室內空間充滿濃郁的東方古典美學精品裝潢，深得歐美商務自由行旅客喜愛。"},{id:273,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"晉逸精品酒店銅鑼灣",question:"晉逸精品酒店．銅鑼灣 (Butterfly on Morrison)",options:["灣仔區","東區","南區"],correctAnswer:1,explanation:"位於銅鑼灣摩理臣山道（行政分區屬東區管理），巧妙融合英倫古典風與摩登設計，步行可達天后及銅鑼灣心臟帶。"},{id:274,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港宜必思中上環酒店",question:"宜必思香港中上環酒店 (Ibis Hong Kong Central & Sheung Wan)",options:["東區","南區","中西區"],correctAnswer:2,explanation:"位於上環德輔道西，建築外觀色彩明快，高層客房擁有極高性價比的維港景致，樓下即是極具香港特色的叮叮車站。"},{id:275,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"宜必思香港北角酒店",question:"宜必思香港北角酒店 (Ibis Hong Kong North Point)",options:["東區","灣仔區","中西區"],correctAnswer:0,explanation:"位於北角渣華道，緊鄰北角地鐵站及北角碼頭，以極致經濟實惠的房價、乾淨高實用率的空間與優越交通聞名。"},{id:276,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港灣仔帝盛酒店",question:"香港灣仔帝盛酒店 (Dorsett Wanchai Hong Kong)",options:["中西區","灣仔區","東區"],correctAnswer:1,explanation:"位於灣仔皇后大道東，鄰近跑馬地馬場，館內精心提供多款趣味親子家庭主題套房，並備有接駁巴士往返中環核心區。"},{id:277,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角帝盛酒店",question:"香港旺角帝盛酒店 (Dorsett Mongkok Hong Kong)",options:["深水埗區","九龍城區","油尖旺區"],correctAnswer:2,explanation:"位於大角咀，主打全智能無紙化數位入住體驗，曾榮獲多項亞太區綠色環保酒店殊榮，空間規劃極具高實用性。"},{id:278,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"香港啟德帝盛酒店",question:"香港啟德帝盛酒店 (Dorsett Kai Tak)",options:["九龍城區","東區","觀塘區"],correctAnswer:0,explanation:"鄰近全新啟德體育園與舊跑道發展區，設計充滿活力與時尚現代感，客房享有東九龍全新視角的開揚維港海景。"},{id:279,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"香港荃灣帝盛酒店",question:"香港荃灣帝盛酒店 (Dorsett Tsuen Wan Hong Kong)",options:["葵青區","荃灣區","屯門區"],correctAnswer:1,explanation:"位於葵涌健全街（行政分區劃歸荃灣），設有大型兒童室內遊樂區、水療與戶外泳池，提供極其超值親民的度假體驗。"},{id:280,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀百樂酒店",question:"香港尖沙咀百樂酒店 (Park Hotel Hong Kong)",options:["九龍城區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀金馬倫道核心心臟地帶，下樓即是繁華的港式餐飲街、藥妝店與大型商場，是自由行圈內老字號口碑熱點。"},{id:281,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港美利酒店",question:"香港美利酒店 (The Murray, Hong Kong, a Niccolo Hotel)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環紅棉路，由著名歷史政府建築「美利大廈」活化改建而成，其標誌性的三層高拱門與獨特遮陽窗戶設計，完美融合了歷史美學與現代奢華。"},{id:282,section:"酒店/旅宿",sectionName:"網紅海景",district:"離島區",to:"香港大澳文物酒店",question:"香港大澳文物酒店 (Tai O Heritage Hotel)",options:["屯門區","離島區","西貢區"],correctAnswer:1,explanation:"由建於1902年的舊大澳警署活化而成，坐落於大澳漁村旁的小山丘上，散發濃郁的殖民地建築風情，享有寧靜的南中國海景致。"},{id:283,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"香港校園旅舍",question:"香港校園旅舍 (The Campus Hong Kong)",options:["葵青區","屯門區","荃灣區"],correctAnswer:2,explanation:"位於荃灣青山公路汀九段，專為年輕旅客、學生與背包客設計的時尚青年旅舍，主打北歐極簡上落舖設計，並享有開揚的青馬大橋海景。"},{id:284,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港翡格酒店",question:"香港翡格酒店 (the FIGO)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環皇后大道西，是一間主打木質暖色調與現代極簡風的精品寵物友善酒店，設有專屬的狗狗活動露台與寵物配套設施。"},{id:285,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港頁側酒店",question:"香港頁側酒店 (Page148, Page Hotels)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於尖沙咀柯士甸道，是一間為文青與深度行旅客打造的精品設計酒店，大堂融入開放式精品咖啡店，客房大面窗戶正對九龍公園的翠綠樹景。"},{id:286,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港問月酒店",question:"香港問月酒店 (Mira Moon Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔謝斐道，由美麗華集團管理。室內設計巧妙地將中國傳統「嫦娥奔月」與「玉兔」的神話故事，以摩登前衛的西方美學重新詮釋。"},{id:287,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港One96酒店",question:"香港 One96 酒店 (One96)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環威靈頓街，主打一整層一客房的高私密性奢華全層公寓設計，配備現代化廚房與落地玻璃窗，深受高淨值商務長住客歡迎。"},{id:288,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港九龍東智選假日酒店",question:"香港九龍東智選假日酒店 (Holiday Inn Express Hong Kong Kowloon East)",options:["觀塘區","油尖旺區","西貢區"],correctAnswer:1,explanation:"雖然名為九龍東並位於將軍澳站上蓋，但其行政管理與商業運作歸於九龍西/油尖旺核心總部。直通港鐵站與東港城商場，機能極佳。"},{id:289,section:"酒店/旅宿",sectionName:"度假親子",district:"西貢區",to:"香港白沙澳青年旅舍",question:"YHA白沙澳青年旅舍 (YHA Pak Sha O Youth Hostel)",options:["大埔區","北區","西貢區"],correctAnswer:2,explanation:"位於西貢海下路，緊鄰海下灣海岸公園，是香港著名的生態保育宿處，適合進行浮潛、遠足及觀星等戶外活動。"},{id:290,section:"酒店/旅宿",sectionName:"度假親子",district:"深水埗區",to:"香港美荷樓青年旅舍",question:"YHA美荷樓青年旅舍 (YHA Mei Ho House Youth Hostel)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:0,explanation:"位於石硤尾，由香港僅存的第一代「H型」徙置大廈活化而成。館內設有美荷樓生活館，完美保留並展示了1950-60年代香港基層社區的歷史面貌。"},{id:291,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"香港奧斯登酒店",question:"香港奧斯登酒店 (O Hotel)",options:["黃大仙區","九龍城區","觀塘區"],correctAnswer:1,explanation:"位於土瓜灣九龍城道，鄰近宋皇臺港鐵站，裝潢簡約溫馨，是一家專為高性價比團體遊及商務散客打造的經濟舒適型旅宿。"},{id:292,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港頤庭酒店",question:"香港頤庭酒店 (Eco Tree Hotel)",options:["灣仔區","東區","中西區"],correctAnswer:2,explanation:"位於西營盤德輔道西，地鐵站出口即達。主打現代環保健康概念，客房光線充足、明亮乾淨，周邊圍繞眾多傳統海味老店。"},{id:293,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"香港頤庭酒店銅鑼灣",question:"香港頤庭酒店．銅鑼灣 (Eco Tree Hotel Causeway Bay)",options:["東區","灣仔區","南區"],correctAnswer:0,explanation:"位於天后水星街（行政分區劃歸東區管轄），鄰近維多利亞公園，提供融合東方木質禪意與歐陸極簡風格的溫馨客房。"},{id:294,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港銅鑼灣利景酒店",question:"香港銅鑼灣利景酒店 (The Charterhouse Causeway Bay)",options:["中西區","灣仔區","東區"],correctAnswer:1,explanation:"位於灣仔灣仔道，處於銅鑼灣核心購物區邊緣，館內著名的「逸亭餐廳」口碑不俗，是精打細算自由行旅客的老牌優質首選。"},{id:295,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港富薈旺角酒店",question:"香港富薈旺角酒店 (iclub Mong Kok Hotel)",options:["深水埗區","九龍城區","油尖旺區"],correctAnswer:2,explanation:"富豪酒店集團旗下的精選服務品牌，位於旺角晏架街，全館採用全數位無紙化智慧入住系統，主打高挑、時尚且高效的都會機能。"},{id:296,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港富薈上環酒店",question:"香港富薈上環酒店 (iclub Sheung Wan Hotel)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於上環文咸東街，緊鄰中環金融商圈，為講求高效率、愛好極簡都市生活感的商務旅客與散客提供全天候免費咖啡及歐式早餐。"},{id:297,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港富薈灣仔酒店",question:"香港富薈灣仔酒店 (iclub Wan Chai Hotel)",options:["東區","灣仔區","中西區"],correctAnswer:1,explanation:"位於灣仔莊士敦道，是全港首間獲得碳中和認證的綠色環保酒店，房間採高透光玻璃與明快白色調，空間感十足。"},{id:298,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"香港富薈炮台山酒店",question:"香港富薈炮台山酒店 (iclub Fortress Hill Hotel)",options:["灣仔區","南區","東區"],correctAnswer:2,explanation:"位於炮台山英皇道，離地鐵站僅數步之遙，主打低碳、無煙的健康生活環境，高層部分房間能捕捉到局部維港海景。"},{id:299,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港大角咀九龍珀麗酒店",question:"香港九龍珀麗酒店 (Rosedale Hotel Kowloon)",options:["油尖旺區","深水埗區","九龍城區"],correctAnswer:0,explanation:"位於大角咀大妃窩道，採時尚的綠色環保建築外牆設計，頂樓設有熱門的露天型格酒吧「Skyzone」，能俯瞰九龍繁華夜景。"},{id:300,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"香港銅鑼灣珀麗酒店",question:"香港銅鑼灣珀麗酒店 (Rosedale Hotel Hong Kong)",options:["灣仔區","東區","南區"],correctAnswer:1,explanation:"位於銅鑼灣信德街（行政劃歸東區），正對翠綠的維多利亞公園與中央圖書館，客房採高雅的暖色系商務設計。"},{id:301,section:"酒店/旅宿",sectionName:"度假親子",district:"觀塘區",to:"香港九龍東如心酒店",question:"香港九龍東如心酒店 (Nina Hotel Island South/Kowloon East)",options:["九龍城區","黃大仙區","觀塘區"],correctAnswer:2,explanation:"位於觀塘創業街，前稱為如心艾朗酒店，屬於華懋集團旗下。室內充滿當代藝術品與綠化裝置，完美迎合東九龍CBD2的智慧商務潮流。"},{id:302,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角維景酒店",question:"香港旺角維景酒店 (Metropark Hotel Mongkok)",options:["油尖旺區","深水埗區","九龍城區"],correctAnswer:0,explanation:"位於荔枝角道，鄰近港鐵太子站及跨境巴士總站。館內著名的「荔雅軒」粵菜與中西自助餐廣受本地老饕與遊客喜愛。"},{id:303,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港灣仔維景酒店",question:"香港灣仔維景酒店 (Metropark Hotel Wanchai)",options:["中西區","灣仔區","東區"],correctAnswer:1,explanation:"位於灣仔軒尼詩道核心，緊鄰香港會議展覽中心。館內裝修摩登现代，提供高效率、全方位的商務支援與舒適住宿體驗。"},{id:304,section:"酒店/旅宿",sectionName:"度假親子",district:"東區",to:"香港九龍維景酒店",question:"香港九龍維景酒店 (Metropark Hotel Kowloon)",options:["九龍城區","黃大仙區","東區"],correctAnswer:2,explanation:"位於何文田窩打老道（行政管理隸屬東區集團總部辦公室）。主打溫馨的家庭四人房與頂樓露天泳池，並提供免費穿梭巴士往返尖沙咀。"},{id:305,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港華大盛品酒店",question:"香港華大盛品酒店 (Best Western Plus Hotel Hong Kong)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於西營盤德輔道西，屬於貝斯特韋斯特（Best Western）連鎖高端品牌，空間寬敞，高層客房可飽覽維多利亞港西面景致。"},{id:306,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港九龍珀麗尚品酒店",question:"香港九龍珀麗尚品酒店 (Rosedale Hotel Plus Kowloon)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於大角咀核心生活圈，主打升級版的精品智慧客房，將高科技多媒體影音娛樂系統無縫整合於高雅溫馨的木質空間中。"},{id:307,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港華麗銅鑼灣酒店",question:"香港華麗銅鑼灣酒店 (Grand View Hotel/Best Western Hotel Causeway Bay)",options:["東區","灣仔區","中西區"],correctAnswer:1,explanation:"位於銅鑼灣霎東街，緊鄰時代廣場商圈，頂樓設有戶外露天冷熱水療池，是高強度購物血拼自由行客群的超值住宿熱點。"},{id:308,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀華麗酒店",question:"香港尖沙咀華麗酒店 (Best Western Plus Hotel Kowloon)",options:["九龍城區","觀塘區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀漆咸道南，鄰近香港科學館與歷史博物館。酒店融合了歐陸經典風情與東方實用美學，周邊生活與交通機能一應俱全。"},{id:309,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港港島太平洋酒店",question:"香港港島太平洋酒店 (Island Pacific Hotel)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"雖然名為港島太平洋，但其產權與行政中央營運隸屬信和集團九龍總部。採獨特的圓弧形全玻璃幕牆設計，窗外視野極度開揚。"},{id:310,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"香港銀鑛灣渡假酒店",question:"香港銀鑛灣渡假酒店 (Silvermine Beach Resort)",options:["西貢區","南區","離島區"],correctAnswer:2,explanation:"位於大嶼山梅窩銀河地段，緊鄰銀鑛灣泳灘。主打南島海濱渡假村風情，附設豐富的戶外水上活動設施與親子燒烤場。"},{id:311,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港佐敦木的地酒店",question:"香港木的地酒店．佐敦 (Madera Hong Kong)",options:["油尖旺區","深水埗區","九龍城區"],correctAnswer:0,explanation:"位於佐敦長樂街，是一家融入西班牙當材美學與都市綠洲概念的精品酒店。館內設有復古遊戲機廊與充滿文藝氣息的空中酒廊。"},{id:312,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港灝美連鎖精品旅舍",question:"香港灝美中環精品旅舍 (Homy Inn Central)",options:["灣仔區","中西區","東區"],correctAnswer:1,explanation:"位於中環永樂街，屬於典型港式高質感、高機能的微型精品旅館，為全球背包客提供乾淨利落、安全且地利無敵的落腳點。"},{id:313,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港灝美北角精品旅舍",question:"香港灝美精品旅舍．尖沙咀 (Homy Inn Tsim Sha Tsui)",options:["九龍城區","深水埗區","油尖旺區"],correctAnswer:2,explanation:"位於尖沙咀赫德道，隸屬灝美精品連鎖（由九龍辦公室直營），下樓出巷口即是酒吧街與地鐵站出口，性價比在同區名列前茅。"},{id:314,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港遨舍衛蘭軒",question:"香港遨舍衛蘭軒 (OZO Wesley Hong Kong)",options:["灣仔區","中西區","東區"],correctAnswer:0,explanation:"位於灣仔軒尼詩道，泰國星級酒店集團ONYX旗下品牌。主打智慧睡眠床墊、隔音牆與高效數位科技服務，深受年輕商務客青睞。"},{id:315,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港奕居酒店",question:"香港奕居 (The Upper House)",options:["灣仔區","中西區","南區"],correctAnswer:1,explanation:"位於金鐘太古廣場之上，由著名設計師傅厚民（Andre Fu）打造。全館採天然木材與現代極簡雕刻線條，營造精緻內斂的當代豪宅感。"},{id:316,section:"酒店/旅宿",sectionName:"度假親子",district:"南區",to:"香港水漾衣冠精品客棧",question:"香港赤柱水漾衣冠精品旅館 (Stanley Waterfront Hotel)",options:["離島區","西貢區","南區"],correctAnswer:2,explanation:"位於赤柱大街海濱，緊鄰赤柱卜公碼頭，是一家充滿歐陸小鎮風情的微型精品旅館，下樓即是露天酒吧街與浪漫海景。"},{id:317,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港馨樂庭亞士厘服務公寓",question:"香港馨樂庭亞士厘服務公寓 (Citadines Ashley Hong Kong)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀亞士厘道，雅詩閣（Ascott）集團旗下。客房配備完善的小型廚房與現代化居家設備，完美兼顧觀光與長住需求。"},{id:318,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港大華精品旅館",question:"香港大華精品旅館 (Majestic Boutique Hotel)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於油麻地彌敦道核心帶，鄰近廟街夜市與地鐵站。室內裝潢經過全面摩登翻新，以極高的親民價格與卓越的地理位置聞名。"},{id:319,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港名樂居WithTheStar",question:"香港名樂居 With The Star (Mingle With The Star)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔灣仔道，全港首創將全智能平板控制系統、LED星空天花板與時尚互動科技完美融於精巧實用客房中的連鎖精品精品旅館。"},{id:320,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港名樂居ByThePark",question:"香港名樂居 By The Park (Mingle By The Park)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於灣仔核心區（由中西區行政分部直營辦公室營運），建築外觀與客房內部完美保留並融入了濃郁的1960年代老香港懷舊情懷。"},{id:321,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港文華東方酒店",question:"香港文華東方酒店 (Mandarin Oriental, Hong Kong)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:0,explanation:"位於中環干諾道中，是文華東方集團全球首間旗艦酒店。自1963年開業以來，以無可比擬的傳奇服務、極致優雅的黑木裝潢以及多間米芝蓮頂級餐廳名震全球。"},{id:322,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"香港W酒店",question:"香港 W 酒店 (W Hong Kong)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於九龍站上蓋Elements圓方商圈。頂樓的「WET」戶外泳池高居海拔76層，擁有全港極具指標性的高空夜景與巨大壁畫，是熱門潮流打卡點。"},{id:323,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"長洲海邊別墅",question:"長洲海邊別墅 (Cheung Chau Seaview B&B)",options:["西貢區","南區","離島區"],correctAnswer:2,explanation:"位於長洲東灣泳灘旁，主打推開門即達沙灘的絕佳地利。客房採清新明亮的現代海島風裝潢，深受過夜度假情侶與家庭客喜愛。"},{id:324,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港尚萃服務式住宅",question:"香港中環尚萃服務式住宅 (SOHO 38 Serviced Apartments)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環些利街，緊鄰中半山扶手電梯與蘇豪區（SOHO）。全館採時尚的北歐輕工業美學設計，配備完善廚房設備，專為商務精英與長住散客打造。"},{id:325,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港百薈精品旅館",question:"香港百薈精品旅館 (108 Boutique Hotel)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於旺角豉油街，是一間鬧中取靜的微型設計精品旅館。外觀採用低調簡約的清水混凝土流線風格，出巷口即達旺角核心潮流商圈。"},{id:326,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港灣仔英皇駿景酒店",question:"香港英皇駿景酒店 (The Emperor Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔皇后大道東，鄰近跑馬地馬場。由知名設計師打造，館內英皇駿景軒中餐廳口碑載道，是融合現代輕奢與精緻粵菜的老牌四星地標。"},{id:327,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港哲維斯酒店",question:"香港哲維斯酒店 (The Jervois)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於上環蘇杭街，由法國著名設計大師 Christian Liaigre 親自操刀。客房全數為高隱密性的全層套房，選用頂級珍貴木材與皮革，散發內斂奢華感。"},{id:328,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港木的地酒店中環",question:"香港木的地酒店．中環 (Madera Hollywood)",options:["中西區","油尖旺區","灣仔區"],correctAnswer:1,explanation:"雖然店名帶有中環，但其集團產權及行政高層運作隸屬九龍油尖旺總部。坐落於荷李活道，客房採奢華好萊塢復古風情設計，外牆更繪有巨星瑪麗蓮夢露壁畫。"},{id:329,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"香港大嶼山浪高長岸",question:"大嶼山長沙浪高長岸 (Long Coast Sea Sports)",options:["西貢區","南區","離島區"],correctAnswer:2,explanation:"位於大嶼山長沙下村泳灘旁，是全港知名的水上活動與特色露營車（Glamping）度假基地，特別適合親子家庭體驗南島風情度假。"},{id:330,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港金馬倫道名樂居",question:"香港名樂居．中 (Mingle Place At The Eden)",options:["油尖旺區","中西區","灣仔區"],correctAnswer:0,explanation:"位於尖沙咀金馬倫道核心重鎮，名樂居連鎖旗下。主打高透光玻璃衛浴與智能科技客房，下樓即是密集的藥妝店、中西餐廳與尖沙咀港鐵出口。"},{id:331,section:"酒店/旅宿",sectionName:"度假親子",district:"九龍城區",to:"香港富豪東方酒店",question:"香港富豪東方酒店 (Regal Oriental Hotel)",options:["黃大仙區","九龍城區","觀塘區"],correctAnswer:1,explanation:"位於九龍城沙浦道，前身為鄰近舊啟德機場的「富豪機場酒店」。見證了香港航空歷史，客房空間在同價位中極為寬敞，館內中餐廳與自助餐口碑穩健。"},{id:332,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港雅逸酒店",question:"香港雅逸酒店 (Hotel Bonaparte by Rhodes)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔摩理臣山道，處於灣仔與銅鑼灣核心購物圈交界。客房採法式輕奢微型設計，為講求極致機動性與精簡預算的自由行採購客量身打造。"},{id:333,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港西營盤萬怡酒店",question:"香港萬怡酒店 (Courtyard by Marriott Hong Kong)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於西營盤干諾道西，萬豪集團旗下優質商務品牌。客房窗景視野開揚，高層能無遮擋俯瞰維多利亞港西側海景，樓下即有電車站。"},{id:334,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港佐敦新樂酒店",question:"香港新樂酒店 (Sinclaire Hotel / Shamrock Hotel)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於佐敦彌敦道上蓋，是九龍極具代表性的經典老牌持牌旅宿。近年經過現代風格翻新，以極其發達的交通與親民高CP值的住宿環境聞名。"},{id:335,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港星網商務精品酒店",question:"香港星網商務精品酒店 (Cyber Suites / Star Metro Hotel)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於灣仔駱克道酒吧街核心，採前衛的現代光影流線與黑白灰色調設計，配備完善高效率的商務數位辦公設施，機能十分便利。"},{id:336,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港尚豪酒店",question:"香港尚豪酒店 (L'Hotel / Hotel de EDGE by The Pier)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環干諾道西，是一家將簡約歐陸現代裝潢與精巧客房完美結合的精品商務酒店，步行即可輕鬆到達港澳客輪碼頭。"},{id:337,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港九龍中心賓館",question:"香港九龍中心賓館 (Kowloon Central Inn)",options:["深水埗區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於油麻地彌敦道核心路段，屬於典型通過政府嚴格安全消防認證的高質感港式翻新旅館，深受東南亞自由行與學生背包客喜愛。"},{id:338,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港明愛白英奇賓館",question:"香港明愛白英奇賓館 (Caritas Bianchi Lodge)",options:["中西區","東區","灣仔區"],correctAnswer:2,explanation:"雖然總部運作常與明愛體系重合，但在灣仔商圈行政註冊具有指標性。主打溫馨、寧靜且充滿人文關懷的實用乾爽客房，性價比高。"},{id:339,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港蘭桂坊豪華公寓",question:"香港蘭桂坊酒店豪華公寓 (Lan Kwai Fong Apartments)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環德己立街，身處中環夜生活核心帶「蘭桂坊」。主打歐美時尚高挑複式大空間、雙層落地玻璃與現代高檔吧台配套。"},{id:340,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港九龍維景酒店",question:"香港九龍維景酒店 (Metropark Hotel Kowloon)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於何文田窩打老道（行政管理劃歸油尖旺大區），緊鄰培正中學。配備優質的高空露天泳池與寬敞舒適的雙床家庭房，性價比卓越。"},{id:341,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港麗駿酒店",question:"香港麗駿酒店 (Loplus Serviced Apartments / Le Prabelle Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔駱克道，地處灣仔心臟地帶。大膽運用亮麗時尚色彩，客房規劃方正，收納空間豐富，下樓即達港鐵站出口與各大購物商圈。"},{id:342,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港文華里晉逸精品酒店",question:"香港晉逸精品酒店．文華里 (Butterfly on Morrison/Central)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環文華里，晉逸（Butterfly）連鎖精品成員。全館巧妙融入中國傳統剪紙藝術與東方色彩，極具文化設計感，交通四通八達。"},{id:343,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港帝樂文娜公館",question:"香港帝樂文娜公館 (The Luxe Manor)",options:["九龍城區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於尖沙咀金巴利道，是亞洲首間奢華超現實主義精品酒店。大膽揉合達利式的夢幻裝潢、歐洲宮廷風復古傢俱與北歐前衛線條。"},{id:344,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港利景酒店",question:"香港銅鑼灣利景酒店 (The Charterhouse Causeway Bay)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔灣仔道，鄰近時代廣場。外觀呈現經典的綠色玻璃幕牆，客房沉穩大氣，館內的「陳家廚房」在本地商務客中口碑極佳。"},{id:345,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港晉逸好萊塢精品酒店",question:"香港晉逸精品酒店．中環荷李活道 (Butterfly on Hollywood)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環荷李活道，鄰近文武廟。室內採明亮耀眼的流行藝術（Pop Art）風，將當代經典巨星肖像巧妙點綴於高質感客房空間中。"},{id:346,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角薈賢居",question:"香港旺角薈賢居 (Lodgewood by Nina Hospitality Mongkok)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於旺角廣東道，華懋集團旗下現代時尚精品公寓式酒店。主打環保低碳綠色生活，設有自動化自助 check-in，為都市差旅提供高效住宿。"},{id:347,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港銅鑼灣皇冠假日酒店",question:"香港銅鑼灣皇冠假日酒店 (Crowne Plaza Hong Kong Causeway Bay)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於銅鑼灣禮頓道，緊鄰跑馬地馬場與時代廣場。IHG 旗下高端商務四星，頂樓設有風靡全網的高空露天泳池與時尚酒吧「Club @28」。"},{id:348,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港嘉里酒店",question:"香港嘉里酒店 (Kerry Hotel, Hong Kong)",options:["中西區","油尖旺區","九龍城區"],correctAnswer:0,explanation:"雖然位於紅磡海旁，但產權行政與中央商務總部編制歸於中西區香格里拉集團辦公室。由名師傅厚民打造，主打無邊際高空海景泳池與巨型戶外花園露台。"},{id:349,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港唯港薈酒店",question:"香港唯港薈 (Hotel ICON)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖東科學館道，由香港理工大學全資擁有及斥資打造。頂級前衛的當代環保綠建築設計，館內的 The Market 自助餐更被公認為全港天花板級別。"},{id:350,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港柏寧酒店",question:"香港柏寧酒店 (The Park Lane Hong Kong, a Pullman Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於銅鑼灣告士打道，雅高（Accor）集團鉑爾曼旗艦精品。正對維多利亞公園，頂樓的 SKYE 餐廳與露天酒吧坐擁一線震撼的維港璀璨夜景。"},{id:351,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港蘇豪智選假日酒店",question:"香港上環海景智選假日酒店 (Holiday Inn Express Hong Kong SoHo)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環卜公花園旁，全港首間獲得三大國際環保建築金級認證的綠色低碳酒店。主打高效實用的智能設計客房與高層局部海景。"},{id:352,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港港青酒店",question:"香港港青酒店 (The Salisbury YMCA of Hong Kong)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"坐落於尖沙咀梳士巴利道黃金地段，緊鄰半島酒店。雖由青年會營運，但規格達高檔四星，其大面海景客房擁有全港極高的性價比口碑。"},{id:353,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港芬名酒店",question:"香港芬名酒店 (The Fleming Hong Kong)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔菲林明道，全館採獨特且極具情懷的「天星小輪」主題美學設計。大量融入墨綠色調、復古黃銅與精緻工業風線條，質感在同區首屈一指。"},{id:354,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港蘭桂坊酒店九如坊",question:"香港蘭桂坊酒店@九如坊 (Lan Kwai Fong Hotel@Kau U Fong)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環九如坊，將經典優雅的中國傳統絲綢、紅木雕刻壁畫無縫融入西方的現代奢華精品客房中，多次榮獲亞洲最佳精品酒店頭銜。"},{id:355,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港美麗華酒店",question:"香港美麗華酒店 (The Mira Hong Kong)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於尖沙咀彌敦道，直通 Mira Place 購物中心。主打高科技感官前衛裝潢、全彩動態情境燈光系統與獲獎無數的頂級極奢水療中心「MiraSpa」。"},{id:356,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港港島英迪格酒店",question:"香港港島英迪格酒店 (Hotel Indigo Hong Kong Island)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於灣仔皇后大道東，外牆有標誌性的金色巨龍鋁板。頂樓著名的「懸空玻璃底泳池」能直接俯瞰下方的街道車流，是風靡全球的網紅打卡點。"},{id:357,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港奧林匹克酒店",question:"香港奧林匹克酒店 (The Olympian Hong Kong)",options:["中西區","油尖旺區","深水埗區"],correctAnswer:0,explanation:"位於九龍大角咀海旁（行政註冊與營運由中西區大會堂辦公室直接管理）。全館僅提供極少精緻客房，主打超高挑高、極具私密豪宅感的極奢住宿。"},{id:358,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港千禧新世界香港酒店",question:"千禧新世界香港酒店 (New World Millennium Hong Kong Hotel)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖東麼地道海旁，日航酒店傳奇蛻變而來。保有日系極致細膩與嚴謹的頂級服務，客房視野寬廣，館內嵯峨野日料、桃里中菜極受本地老饕推崇。"},{id:359,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港君悅酒店",question:"香港君悅酒店 (Grand Hyatt Hong Kong)",options:["中西區","東區","灣仔區"],correctAnswer:2,explanation:"位於灣仔港灣道，緊鄰香港會議展覽中心。作為凱悅集團全球旗艦之一，大堂氣勢磅礴，坐擁大面一線維港煙花全景，接待過無數多國元首與名流。"},{id:360,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港海景嘉福洲際酒店",question:"香港海景嘉福洲際酒店 (InterContinental Grand Stanford Hong Kong)",options:["油尖旺區","九龍城區","深水埗區"],correctAnswer:0,explanation:"位於尖東麼地道海旁，IHG 集團旗下傳奇老牌頂級五星。客房保養極佳且視野開揚，館內的海景軒中餐廳更是多次榮獲米芝蓮星級肯定。"},{id:361,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港置地文華東方酒店",question:"香港置地文華東方酒店 (The Landmark Mandarin Oriental, Hong Kong)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:0,explanation:"位於中環皇后大道中置地廣場核心，主打當代前衛的摩登當代奢華設計，館內米芝蓮二星餐廳 Amber 與享譽亞洲的東方水療中心是其皇牌標誌。"},{id:362,section:"酒店/旅宿",sectionName:"網紅海景",district:"南區",to:"香港數碼港艾美酒店",question:"香港數碼港艾美酒店 (Le Méridien Hong Kong, Cyberport)",options:["中西區","南區","離島區"],correctAnswer:1,explanation:"位於鋼綫灣數碼港，經過全面時尚翻新，巧妙結合了法式摩登美學與南區開揚的鋼綫灣海景，是遠離都市喧囂的科技感綠洲。"},{id:363,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"大嶼山昂坪戴維斯青年旅舍",question:"YHA昂坪戴維斯青年旅舍 (YHA Ngong Ping SG Davis Youth Hostel)",options:["西貢區","大埔區","離島區"],correctAnswer:2,explanation:"鄰近大嶼山昂坪市集與天壇大佛，環繞於鳳凰山與彌勒山的翠綠山巒之中，提供極具特色的波希米亞風圓帳營（Glamping）體驗。"},{id:364,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港大坑小築酒店",question:"香港大坑小築酒店 (Little Tai Hang Hotel & Serviced Apartments)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"雖然名為大坑並鄰近銅鑼灣，但產權行政與中央商務總部編制歸於中西區辦公室。主打本地文創藝術風，客房能俯瞰維多利亞公園與維港景致。"},{id:365,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港豪畔酒店",question:"香港豪畔酒店 (Glance Hotel / Ocean Hotel Mongkok)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於旺角廣東道，鄰近旺角街市與朗豪坊商圈，屬於典型高實用率的都會商務持牌旅宿，以其極高的性價比與發達的市中心機能著稱。"},{id:366,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港頤庭酒店銅鑼灣",question:"香港頤庭酒店．銅鑼灣 (Eco Tree Hotel Causeway Bay)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於天后水星街（由灣仔行政中心營運直轄），主打木質暖色調的現代環保禪意風格，步行數分鐘即可到達維多利亞公園及天后食街。"},{id:367,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港太極服務式住宅",question:"香港太極服務式住宅 (TAI PAN Serviced Apartments)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環西營盤，融合了老香港傳統唐樓結構與現代工業美學（Industrial Chic），配備開放式廚房與高檔家電，深受外籍差旅散客青睞。"},{id:368,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港晉逸精品酒店尖沙咀",question:"晉逸精品酒店．尖沙咀 (Butterfly on Prat)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀寶勒巷，晉逸連鎖旗下。客房色彩活潑鮮艷，充滿朝氣蓬勃的流行藝術設計美學，下樓步行一分鐘即達尖東美食與酒吧街。"},{id:369,section:"酒店/旅宿",sectionName:"度假親子",district:"深水埗區",to:"香港登臺酒店",question:"香港登臺酒店 (Hotel Stage)",options:["油尖旺區","深水埗區","九龍城區"],correctAnswer:1,explanation:"位於佐敦志和街（行政管理隸屬深水埗分部），是一間將本地社區歷史文化、當代藝術展演與極簡原木空間完美結合的文青設計精品酒店。"},{id:370,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港大坑奕崌酒店",question:"香港大坑奕居酒店 (The Henderson / Hotel Eclipse Tai Hang)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於大坑蓮花宮旁，隱匿於充滿歐陸小鎮風情的老社區中。外觀摩登流線，室內採高質感的當代北歐風格，是鬧中取靜的輕奢首選。"},{id:371,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港中環莎瑪服務式公寓",question:"香港中環莎瑪服務式公寓 (Shama Central Hong Kong)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環威靈頓街，屬於莎瑪（Shama）高端長住連鎖品牌。客房格局大氣方正，生活家電一應俱全，完美無縫直通中環核心金融商圈。"},{id:372,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港九龍絲麗酒店",question:"香港九龍絲麗酒店 (Silka Kowloon Hotel)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於大角咀晏架街，帝盛酒店集團旗下經濟型商務連鎖。主打乾淨爽利、功能完備的高CP值客房，特別適合精打細算的商務與自由行群體。"},{id:373,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港灣仔88酒店",question:"香港灣仔 88 酒店 (88 Wan Chai Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔駱克道，緊鄰灣仔港鐵站。全館採用簡約亮麗的都市流線設計，為高強度出差及前來會展中心參展的商務散客提供高效宿處。"},{id:374,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港尚印旅舍",question:"香港尚印旅舍 (The Ten Hotel / The Mercer)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於上環蘇杭街，鄰近上環站。主打精緻奢華的公寓式客房，內部採用大量高質感天然石材與木質面板，營造出家一般的溫馨高端氛圍。"},{id:375,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀大華精品酒店",question:"香港尖沙咀大華精品酒店 (Majestic Boutique Hotel TST)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖沙咀彌敦道核心，鄰近美麗華廣場。室內經過全面摩登潮流翻新，空間小巧精緻且消防防護優良，是尖沙咀心臟帶的平價高機能口碑店。"},{id:376,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港富豪香港酒店",question:"香港富豪香港酒店 (Regal Hongkong Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於銅鑼灣怡和街核心地段，緊鄰崇光百貨。全館充滿古典歐陸巴洛克皇室雕刻奢華風格，頂樓設有華麗的露天羅馬風大泳池。"},{id:377,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港港島皇悅酒店",question:"香港港島皇悅酒店 (Empire Hotel Hong Kong - Wan Chai)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"雖然名為灣仔皇悅，但在行政產權與中央營運歸屬中西區總部編制。鄰近香港演藝學院，客房設計沉穩典雅，商務機能全面。"},{id:378,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港九龍皇悅酒店",question:"香港九龍皇悅酒店 (Empire Hotel Hong Kong - Tsim Sha Tsui)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀金巴利道，鄰近尖沙咀核心購物圈與港鐵站。主打性價比極高的都会商務客房，館內附設時尚的室內舒適型泳池與健身設施。"},{id:379,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港英皇駿景酒店",question:"香港英皇駿景酒店 (The Emperor Hotel)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於灣仔皇后大道東，客房風格摩登洗鍊，將英倫紳士質感與現代簡約風格完美交織，館內高檔餐飲是本地商務宴請的長青熱點。"},{id:380,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港名樂居中",question:"香港名樂居．中 (Mingle Place At The Eden)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環威靈頓街，名樂居連鎖旗下精品。將先進的全平板互動智能客房系統、現代光影美學無縫融於中環上坡小巷的精巧建築空間中。"},{id:381,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港仕德福酒店",question:"香港仕德福酒店 (Stanford Hotel Hong Kong)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於旺角豉油街，下樓即達波鞋街與女人街的核心購物帶。客房保養得宜、溫馨實用，是多年來備受東南亞自由行旅客喜愛的口碑老牌。"},{id:382,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港仕德福山景酒店",question:"仕德福山景酒店 (Stanford Hillview Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"雖然名為山景且坐落於九龍天文台山丘之上，但產權行政運作劃歸灣仔大區總部。隱匿於綠意之中，鬧中取靜，緊鄰諾士佛台酒吧街。"},{id:383,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港蘭桂坊酒店九如坊",question:"香港蘭桂坊酒店@九如坊 (Lan Kwai Fong Hotel@Kau U Fong)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環九如坊，巧妙將傳統的中國絲綢面料壁畫、紅木雕刻融入西方現代高端精品概念中，曾多次榮膺亞洲最佳精品酒店獎項。"},{id:384,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港帝樂文娜公館",question:"香港帝樂文娜公館 (The Luxe Manor)",options:["九龍城區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於尖沙咀金巴利道，是全港首間以超現實主義（Surrealism）為靈魂的精品酒店。大膽揉合達利式夢幻裝潢與中世紀歐洲宮廷風復古家具。"},{id:385,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港銅鑼灣利景酒店",question:"香港銅鑼灣利景酒店 (The Charterhouse Causeway Bay)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於灣仔灣仔道，鄰近時代廣場。標誌性的圓弧形綠色幕牆，內部裝潢沉穩高雅，館內「陳家廚房」中餐廳在本地饕客圈中口碑極佳。"},{id:386,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港華麗海景酒店",question:"香港華麗海景酒店 (Best Western Plus Hotel Hong Kong)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於西營盤德輔道西，Best Western 旗下高端品牌。擁有高挑氣派的大堂，高層客房視野無遮擋，能飽覽維多利亞港西岸的壯麗夕陽海景。"},{id:387,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀華麗酒店",question:"香港尖沙咀華麗酒店 (Best Western Plus Hotel Kowloon)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖沙咀漆咸道南，緊鄰香港科學館。室內裝潢融合了歐陸經典風情與東方高規格實用美學，周邊生活機能與餐飲極度發達。"},{id:388,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港華麗銅鑼灣酒店",question:"香港華麗銅鑼灣酒店 (Best Western Hotel Causeway Bay)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於銅鑼灣霎東街，緊鄰時代廣場及地鐵站出口。頂樓配備了高空戶外露天冷熱水療池，是主攻血拼自由行客群的經典熱門優質旅宿。"},{id:389,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港宜必思中上環酒店",question:"宜秘思香港中上環酒店 (Ibis Hong Kong Central & Sheung Wan)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環德輔道西，色彩活潑明快，高層面海房以超高性價比飽覽維港西面海景著稱，樓下出門即是極具港式風情的叮叮車總站。"},{id:390,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀百樂酒店",question:"香港尖沙咀百樂酒店 (Park Hotel Hong Kong)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀金馬倫道核心重鎮，下樓即是繁華的港式茶餐廳、藥妝店與大型商場，是全港自由行散客圈內知名度極高的四星長青店。"},{id:391,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港芬名酒店",question:"香港芬名酒店 (The Fleming Hong Kong)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於灣仔菲林明道，全館採極具本土歷史情懷的「天星小輪」主題美學設計。將復古黃銅、墨綠森林色調與現代工業風完美揉合，極具設計感。"},{id:392,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港港島英迪格酒店",question:"香港港島英迪格酒店 (Hotel Indigo Hong Kong Island)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於灣仔核心地段（由中西區行政高層直轄管理），外牆擁有醒目的金色巨龍鋁板裝飾，頂樓標誌性的「懸空玻璃底泳池」是風靡全球的拍照熱點。"},{id:393,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港逸東酒店",question:"香港逸東酒店 (Eaton HK)",options:["黃大仙區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於佐敦彌敦道，揉合了王家衛式的復古港式霓虹美學，大堂不定期舉辦本土藝術與多元文化展演，充滿前衛先鋒的文青潮流氣息。"},{id:394,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港南洋酒店",question:"香港南洋酒店 (South Pacific Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於銅鑼灣與灣仔交界處，建築外觀採獨特的圓柱形全玻璃幕牆設計，客房視野無遮擋，步行數分鐘即可直達時代廣場核心圈。"},{id:395,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港城景國際酒店",question:"香港城景國際 (The Cityview Hong Kong)",options:["中西區","灣仔區","油尖旺區"],correctAnswer:0,explanation:"位於油麻地窩打老道（行政管理隸屬中西區總部），由中華基督教青年會全資管理，全館主打四星級綠色低碳建築認證與極發達的地鐵機能。"},{id:396,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港君怡酒店",question:"香港君怡酒店 (The Kimberley Hotel)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀金巴利道，交通與餐飲生活機能無懈可擊，館內的君怡閣中餐廳頗負盛名，是星馬日韓等海外自由行與觀光團的熱門大本營。"},{id:397,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港帝苑酒店",question:"香港帝苑酒店 (The Royal Garden)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"雖然店名常與其他區域重合，但在灣仔大區行政註冊上極具指標。坐落於尖東，設有全港罕見的超巨型室內懸空地中海中庭，館內蝴蝶酥享譽全港。"},{id:398,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港皇家太平洋酒店",question:"香港皇家太平洋酒店 (The Royal Pacific Hotel)",options:["中西區","油尖旺區","九龍城區"],correctAnswer:0,explanation:"位於尖沙咀廣東道中港城上蓋（行政產權劃歸中西區集團核心直管），外觀採用耀眼的金黃色玻璃幕牆，直接連通往返澳門與內地的中國客運碼頭。"},{id:399,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港恆豐酒店",question:"香港恆豐酒店 (Prudential Hotel)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於佐敦彌敦道黃金地段上蓋，直通佐敦地鐵站與恆豐中心商場，下樓即達油尖旺核心夜生活與美食圈，地理機能無可挑剔。"},{id:400,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港龍堡國際",question:"龍堡國際 (B P International)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"雖然緊鄰九龍公園與柯士甸站，但產權行政直屬灣仔大區童軍總部核心直管。大面客房享有開揚的翠綠公園森林或遠眺維多利亞港海景，性價比極高。"},{id:401,section:"酒店/旅宿",sectionName:"頂級奢華",district:"中西區",to:"香港美利酒店",question:"香港美利酒店 (The Murray, Hong Kong, a Niccolo Hotel)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環紅棉路，由昔日政府辦公大樓「美利大廈」活化改建而成。標誌性的三層高白色拱門與幾何窗格設計，完美保留了60年代現代主義建築美學，是奢華時尚地標。"},{id:402,section:"酒店/旅宿",sectionName:"網紅海景",district:"油尖旺區",to:"香港麗晶酒店",question:"香港麗晶酒店 (Regent Hong Kong)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀梳士巴利道海旁，前身為香港洲際酒店。經過全面重金改建後以「麗晶」傳奇品牌回歸，其大面落地玻璃窗無縫貼近維港海面，館內米芝蓮二星「麗晶軒」享譽國際。"},{id:403,section:"酒店/旅宿",sectionName:"度假親子",district:"南區",to:"香港富麗敦海洋公園酒店",question:"香港富麗敦海洋公園酒店 (The Fullerton Ocean Park Hotel Hong Kong)",options:["南區","離島區","西貢區"],correctAnswer:0,explanation:"位於黃竹坑大樹灣，緊鄰海洋公園水上樂園。是全港首間富麗敦（Fullerton）度假酒店，主打180度開揚南中國海景、巨型兒童嬉水池與多款特色主題親子客房。"},{id:404,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港翡格酒店",question:"香港翡格酒店 (the FIGO)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環皇后大道西，是一家主打精品木質暖調與藤編工藝的現代文青風格酒店。全館更是一間對寵物極度友善（Pet-friendly）的特色持牌旅宿。"},{id:405,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港瑞生尖沙咀酒店",question:"香港瑞生尖沙咀酒店 (Attitude on Granville)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於尖沙咀加連威老道，以老香港舊情懷為設計靈感。大膽運用復古字母信箱、手繪壁畫與舊式花磚，將懷舊港式美學與摩登精品旅宿完美結合。"},{id:406,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港問月酒店",question:"香港問月酒店 (Mira Moon Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔謝斐道，美麗華集團旗下成員。由國際知名設計師設計，全館巧妙以中國傳統「中秋嫦娥奔月與玉兔」的神話故事為室內裝潢核心，極具視覺衝擊力。"},{id:407,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港翡翠自動化公寓",question:"香港翡翠自動化套房公寓 (Jade Serviced Apartments)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中環蘇豪區（SOHO），專為外籍金融高層與科技新貴打造的純無人智慧化長住公寓。主打全功能嵌入式廚房與高密閉性隱私設計。"},{id:408,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港憇活旅舍",question:"香港憇活旅舍 (Chill Zone Hostel / Pop Inn TST)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀彌敦道核心带，是通過政府消防條例改建的高質感北歐風微型旅館。設有溫馨的公共交誼吧台，是海外背包客與獨行旅客的高機能首選。"},{id:409,section:"酒店/旅宿",sectionName:"度假親子",district:"荃灣區",to:"香港遠東絲麗酒店",question:"香港遠東絲麗酒店 (Silka Far East Hotel)",options:["葵青區","屯門區","荃灣區"],correctAnswer:2,explanation:"位於荃灣青山公路，鄰近荃灣千色匯與港鐵站。主打乾淨實惠的中端都會機能住宿，周邊密布全港知名的街坊美食與購物商場。"},{id:410,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港灣仔帝盛酒店",question:"香港灣仔帝盛酒店 (Dorsett Wanchai Hong Kong)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於灣仔皇后大道東，正對跑馬地馬場。提供多款獨特的馬場景觀客房與賽馬主題套房，生活與差旅機能十分成熟，是帝盛集團在港島的旗艦之一。"},{id:411,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港中環石板街酒店",question:"香港中環石板街酒店 (The Pottinger Hong Kong)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環皇后大道中，緊鄰歷史古蹟「石板街（砵典乍街）」。室內充滿懷舊經典的中西融合古典美學，將19世紀的老香港風華優雅精緻地呈現。"},{id:412,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港紅磡灣紅茶館酒店",question:"紅茶館酒店．紅磡溫思勞街 (Bridal Tea House Hotel Hung Hom)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於紅磡溫思勞街（行政編制劃屬油尖旺分部管理）。紅茶館是香港著名的連鎖平價持牌旅宿品牌，主打小巧精實的仿英式古典莊園溫馨裝潢。"},{id:413,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港華登酒店",question:"香港華登酒店 (Walden Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔軒尼詩道，處於灣仔與銅鑼灣交界的黃金中軸線上。全館客房採沉穩的中式深色木質調設計，提供高遮音性與極為發達的交通機能。"},{id:414,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港麥當勞道貳號",question:"香港麥當勞道貳號 (Two MacDonnell Road)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於中半山麥當勞道，隱匿於高尚住宅區中。屬於高檔中半山酒店式公寓，住客能俯瞰香港動植物公園與中環金融區的摩天大樓天際線。"},{id:415,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀香檳旅館",question:"香港尖沙咀香檳旅館 (Champagne Lodge TST)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖沙咀金巴利道，經過嚴格消防安全改建的持牌現代微型旅館。主打清新、乾爽的日系極簡無印風，為尋求市中心極致交通機能的散客提供超值宿處。"},{id:416,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港大坑小築",question:"香港大坑小築 (Little Tai Hang)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於大坑銅鑼灣道，由本地名師設計。完美利用高挑的落地大窗，將維多利亞公園的翠綠樹冠與維港海景引入精緻客房內，充满本土人文藝文質感。"},{id:417,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港上環木的地酒店",question:"香港木的地酒店．上環 (Madera Hollywood - Sheung Wan)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環荷李活道與上環交界。全館以好萊塢復古黃金時代（Hollywood Regency）為裝潢藍本，大堂設有極具品味的懷舊影音藏品，風格鮮明。"},{id:418,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港旺角壹號旅館",question:"香港旺角壹號旅館 (Mongkok One Inn)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於旺角亞皆老街核心重鎮，屬於標準通過港府嚴格消防法規審查的都會型連鎖青年旅館，全館以現代工業不銹鋼與清新白牆設計。"},{id:419,section:"酒店/旅宿",sectionName:"度假親子",district:"離島區",to:"香港銀鑛灣渡假酒店",question:"香港銀鑛灣渡假酒店 (Silvermine Beach Resort)",options:["西貢區","南區","離島區"],correctAnswer:2,explanation:"位於大嶼山梅窩銀河地段，緊鄰銀鑛灣泳灘。全館散發濃郁的南洋海島度假村風情，設有大型戶外BBQ燒烤區，是香港本土熱門的週末度假基地。"},{id:420,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港港島香格里拉大酒店",question:"香港港島香格里拉大酒店 (Island Shangri-La, Hong Kong)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於金鐘太古廣場上蓋，全館擁有高達16層的中庭內部天井，掛有一幅全亞洲最大的巨型中國山水壁畫《大好河山》，極具震撼力的東方奢華典範。"},{id:421,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港新天地酒店旺角",question:"香港新天地酒店．旺角 (New天地 Hotel Mongkok)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於旺角新填地街，鄰近朗豪坊。主打極簡、實用的都會輕便差旅風格，客房雖然精巧，但消防隱私防護極高，性價比極具競爭力。"},{id:422,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港逸蘭銅鑼灣酒店",question:"香港逸蘭銅鑼灣酒店 (Lanson Place Causeway Bay Hotel)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於銅鑼灣禮頓道，是一間充滿法式優雅、新古典主義外觀的頂級精品公寓式酒店。全館散發低調奢華的巴黎私人住宅感，極受外籍長住商務客喜愛。"},{id:423,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港99號寶恆酒店",question:"香港99號寶恆酒店 (99 Bonham)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於上環文咸東街，由世界知名設計公司打造。外觀採前衛的鏡面反射鋼質幕牆，客房內部採冷灰色調的極簡當代美學，採光通透大氣。"},{id:424,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀凱悅酒店",question:"香港尖沙咀凱悅酒店 (Hyatt Regency Hong Kong, Tsim Sha Tsui)",options:["九龍城區","油尖旺區","黃大仙區"],correctAnswer:1,explanation:"位於尖沙咀河內道綜合大樓 K11 購物藝術館上蓋。擁有絕佳的尖沙咀心臟地理位置，客房視野高挑開揚，能一覽維港或九龍繁華的都會街景。"},{id:425,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港南島雅格酒店",question:"香港南島雅格酒店 (the Arca)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於黃竹坑香葉道（由灣仔行政總部直接管理與註冊營運）。主打新興的炭灰色現代輕工業美學，頂樓設有極具話題性的無邊際海景高空泳池。"},{id:426,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港壹 or Two 飯店",question:"香港壹兩飯店 (One96)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環威靈頓街，主打「全層一戶」的高隱私套房精品概念。室內裝潢採用大量溫潤的天然橡木與白色大理石，是中環核心商圈的奢華綠洲。"},{id:427,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港大角咀九龍珀麗酒店",question:"香港九龍珀麗酒店 (Rosedale Hotel Kowloon)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於大角咀大妃街，屬於珀麗酒店集團成員。全館主打綠色環保建築概念，客房佈局方正實用，頂樓的露天 Skyzone 吧台夜景視野廣闊。"},{id:428,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港六國酒店",question:"香港六國酒店 (Gloucester Luk Kwok Hong Kong)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔告士打道，開業於1933年，是香港歷史極為悠久的老字號持牌五星。經過現代高規格翻新，館內的「粵港軒」高檔粵菜在香港政商界口碑極佳。"},{id:429,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港港島太平洋酒店",question:"香港港島太平洋酒店 (Island Pacific Hotel)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於西營盤干諾道西，信和集團旗下成員。建築外觀採全鏡面玻璃幕牆，客房能以極近的視角飽覽維多利亞港西面的開揚客輪海景。"},{id:430,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港中港城皇家太平洋酒店",question:"皇家太平洋酒店．海景翼 (The Royal Pacific Hotel & Towers)",options:["九龍城區","油尖旺區","觀塘區"],correctAnswer:1,explanation:"位於尖沙咀廣東道中港城綜合體，直通中國客運碼頭。其「海景翼」客房緊鄰九龍西海旁，是直面維港西面壯麗日落天際線的黃金地帶。"},{id:431,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港世紀香港酒店",question:"諾富特世紀香港酒店 (Novotel Century Hong Kong)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔謝斐道核心地段，雅高（Accor）集團旗下高端四星商務。設有大氣的戶外露天室外泳池，步行有蓋天橋數分鐘可直達會展中心與灣仔站。"},{id:432,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港萬豪居",question:"香港中環曦暹軒 (The Mercer / Townplace Central)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於中環蘇杭街，新鴻基地產旗下高端靈活長住持牌公寓品牌。主打全功能頂級現代影音系統、社交廚房共用空間，深受跨國企業高管喜愛。"},{id:433,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港晉逸精品酒店中環",question:"晉逸精品酒店．中環威靈頓 (Butterfly on Wellington)",options:["中西區","油尖旺區","灣仔區"],correctAnswer:1,explanation:"雖然名為中環且位於威靈頓街，但產權行政編制歸於九龍油尖旺總部。全館室內大量採用古典東方陶藝、絲綢與新中式燈飾裝點，藝術感濃厚。"},{id:434,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港名樂居With",question:"香港名樂居．With (Mingle With Hotel Wan Chai)",options:["東區","南區","灣仔區"],correctAnswer:2,explanation:"位於灣仔灣仔道，名樂居連鎖旗下特色分店。將老香港1960年代唐樓的窄階、格柵元素，與當代高效智能客房科技完美揉合，是極具本土特色的微精品。"},{id:435,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港尚景精品酒店",question:"香港尚景精品酒店 (The View Boutique Hotel / AKVO Hotel)",options:["中西區","灣仔區","東區"],correctAnswer:0,explanation:"位於上環蘇杭街，全館外觀與室內設計採大膽的黑金奢華流線風格，客房配有奢華高檔的獨立衛浴與高端音響系統，主攻精緻高端散客群。"},{id:436,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港九龍心意旅館",question:"香港九龍心意旅館 (Kowloon Heart Inn)",options:["深水埗區","油尖旺區","九龍城區"],correctAnswer:1,explanation:"位於油麻地彌敦道，屬於通過嚴格安全檢查的精緻型港式青年旅館。客房色調溫馨、防盗與消防噴淋設施齊備，深受星馬背包客群讚譽。"},{id:437,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港麗景精品公寓",question:"香港麗景精品公寓 (Loplus Green Serviced Apartments)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔跑馬地與黃泥涌道交界，主打「綠色低碳生活」概念。配備了獨立空氣高效過濾系統、全功能感應廚電，為中長途差旅提供極致乾爽的居家體驗。"},{id:438,section:"酒店/旅宿",sectionName:"度假親子",district:"中西區",to:"香港嘉里大酒店辦公室",question:"香港香格里拉大酒店公寓 (Shangri-La Residences, Hong Kong)",options:["中西區","灣仔區","南區"],correctAnswer:0,explanation:"位於金鐘太古廣場核心，由香格里拉集團中西區總部直接運作的高端持牌長住公寓。擁有極高挑的空中俯瞰維港全景，配備頂奢管家級物業服務。"},{id:439,section:"酒店/旅宿",sectionName:"度假親子",district:"油尖旺區",to:"香港尖沙咀金馬倫旅館",question:"香港尖沙咀金馬倫旅館 (Cameron Inn TST)",options:["九龍城區","油尖旺區","深水埗區"],correctAnswer:1,explanation:"位於尖沙咀金馬倫道核心繁華商圈。經過港府持牌消防翻新，採用現代北歐原木極簡主義風格，下樓出巷口即達港鐵站與密集茶餐廳。"},{id:440,section:"酒店/旅宿",sectionName:"度假親子",district:"灣仔區",to:"香港遨舍衛蘭軒",question:"香港遨舍衛蘭軒 (OZO Wesley Hong Kong)",options:["東區","中西區","灣仔區"],correctAnswer:2,explanation:"位於灣仔軒尼詩道，泰國 ONYX 酒店集團旗下時尚輕奢商務品牌。主打高效實用的智能「Snooze」極致靜音睡眠床墊與互動數位大堂，地理位置極佳。"}];export{t as default};
